INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (1, '小鲫鱼', '一条非常常见的小鱼，孤苦伶仃。只能炖汤。', 1, 10, 100, 500, NULL);
