INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (3, '小虾', '常见的水底生物，除了小了点，谁会不喜欢呢？', 1, 20, 30, 100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (4, '沙丁鱼', '成群结队的小型海鱼，与你最常见面的地方其实在罐头里。', 1, 12, 100, 300, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (5, '小黄鱼', '体色金黄，常见食用鱼，经常出现在烧烤摊。', 1, 18, 150, 400, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (6, '海虾', '比淡水虾稍大，但还是不够吃。', 1, 25, 50, 150, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (7, '破旧的靴子', '谁把靴子扔水里了？还能穿吗？', 1, 1, 200, 800, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (8, '生锈的铁罐', '被水泡得不成样子了，依然恪尽职守，能装水。', 1, 2, 100, 400, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (9, '缠绕的水草', '一团湿漉漉的水生植物，缠上了你的鱼线，解去吧。', 1, 1, 50, 300, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (10, '普通石头', '就是一块普通的石头，沉甸甸的，伤害1D3。', 1, 0, 500, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (11, '罗非鱼', '繁殖能力很强，适应性好，随便吃。', 1, 13, 120, 600, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (12, '鲦鱼', '溪流中常见的小型杂食鱼，希望你钓起来的不是它们的首领……', 1, 8, 20, 80, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (13, '鮈鱼', '生活在水底的小型鲤科鱼，以小钓大的机会！', 1, 9, 30, 100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (14, '银鲈', '沿海常见的小型银色鱼类，它只错在鲜嫩味美。', 1, 16, 130, 450, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (15, '大西洋黄花鱼', '能发出类似蛙鸣的鼓噪声。', 1, 17, 160, 550, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (16, '斑点鱼', '尾鳍基部有个明显的黑斑。这大概是它的专属纹身。', 1, 14, 110, 350, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (17, '食蚊鱼', '以蚊子幼虫为食，体型微小。蚊子的天敌，虽小却有大作用。', 1, 5, 10, 30, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (18, '凤尾鱼', '常被用来制作鱼干或罐头。罐头里的常客，鲜味被封存其中。', 1, 7, 15, 60, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (19, '胡瓜鱼', '体型细长，有一种特殊的黄瓜味。是鱼还是瓜？这是个问题。', 1, 11, 80, 250, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (20, '草鱼', '喜欢吃草的淡水鱼，素食主义者，但肉质一点也不素。', 2, 50, 500, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (21, '鲤鱼', '据说能带来好运。钓到它，今天运气一定不错。毕竟鲤鱼可好吃了。', 2, 60, 600, 2500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (22, '鲢鱼', '头部较大，滤食性鱼类。头大聪明？不，头大好喝汤。', 2, 55, 500, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (23, '鳊鱼', '体型侧扁，味道不错。扁扁的身材，鲜美的味道。', 2, 65, 600, 2500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (24, '鲅鱼', '体型较长，常做熏鱼。熏制之后，风味更佳。', 2, 70, 700, 3000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (25, '带鱼', '身体扁长如带。海里的银色飘带，也是餐桌常客。', 2, 75, 800, 3500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (26, '黄花鱼', '分为大黄鱼和小黄鱼。大小都是蒜瓣肉，鲜嫩无比。', 2, 80, 900, 4000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (27, '鲳鱼', '肉厚刺少。懒人吃鱼首选，放心大口吃。', 2, 85, 1000, 4500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (28, '河豚', '生气时会鼓成一个球，可能有毒！美味与风险并存，非专业勿试。', 2, 40, 300, 1500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (29, '小丑鱼', '和海葵共生，颜色鲜艳。在某个片场似乎是人见人爱的大明星。', 2, 45, 80, 250, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (30, '螃蟹', '横行霸道的甲壳生物。小心它的钳子，小心完了之后就能得到鲜美的肉和黄。', 2, 35, 200, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (31, '河鲈', '广泛分布的淡水掠食性鱼类。水域中的小霸王，钓鱼人的好目标。', 2, 48, 400, 1800, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (32, '蓝鳃太阳鱼', '北美常见的太阳鱼，色彩鲜艳，是水中的一道彩虹。', 2, 42, 350, 1500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (33, '莓鲈', '北美常见的两种太阳鱼，分黑莓鲈和白莓鲈。跟水果没关系哦。', 2, 44, 380, 1600, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (34, '玻璃梭鲈', '眼睛在光下会反光，夜行性，好似暗夜中的幽灵，目光如炬。', 2, 68, 650, 2800, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (35, '牛头鱼', '头大嘴宽，常见的小型鲶鱼。长得像牛头，性格也温和？', 2, 38, 300, 1400, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (36, '羊头鱼', '牙齿像羊齿，能咬碎贝壳。算是海里的“羊”，毕竟专吃硬壳。', 2, 72, 750, 3200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (37, '比目鱼', '眼睛长在同一侧，身体扁平。它眼中的世界是否更加立体呢，只有它才知道了。', 2, 62, 600, 2600, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (38, '黑线鳕', '背部有明显的黑色侧线。这条黑线是它的“单线加长条纹码”。', 2, 58, 550, 2400, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (39, '青鳕', '常见的食用鱼，肉质白色。肉嫩味美的它常常去餐桌上做客。', 2, 52, 500, 2200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (40, '无须鳕', '深水鱼类，作为独立的无须鳕科的下场，仍然是被做成鱼排。', 2, 54, 520, 2300, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (41, '鲭鱼', '体型纺锤，游泳速度快。海中的游泳健将，越游肉质越紧实。', 2, 67, 700, 3100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (42, '斧头鱼', '身体侧扁像斧头，深海发光鱼，是自带光芒的深海“斧头”。', 2, 88, 100, 400, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (43, '鳞鲀', '有一个可以锁定的背鳍棘刺。小心它的“锁喉”绝技。', 2, 78, 800, 3400, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (44, '鲈鱼', '肉质鲜美，适合清蒸。清蒸是对它最大的尊重。', 3, 100, 800, 3000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (45, '黑鱼', '生性凶猛的掠食者。池塘里的恶霸，能制裁它的只有你了！', 3, 150, 1000, 4000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (46, '鳜鱼', '又称桂鱼，名贵食用鱼。桃花流水鳜鱼肥，文人墨客也爱它。', 3, 120, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (47, '胭脂鱼', '色彩艳丽的保护动物，这么美，还是让它留在水里吧，只是它咬钩的时候不这么想。', 3, 180, 1200, 6000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (48, '鲨鱼', '海洋中的顶级掠食者之一。别怕，不是所有鲨鱼都吃人。', 3, 200, 5000, 20000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (49, '金枪鱼', '高速游泳的大型鱼类。寿司店里的贵族，贵是指价格。', 3, 250, 6000, 25000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (50, '石斑鱼', '名贵的海产鱼类，是藏在礁石中的美味。难怪要藏。', 3, 300, 7000, 30000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (51, '鲷鱼', '体色鲜艳，寓意吉祥。过年过节常备，喜庆。', 3, 350, 8000, 35000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (52, '食人鱼', '牙齿锋利，成群时很危险。亚马逊的恐怖传说，但单独一条并不可怕。', 3, 110, 500, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (53, '章鱼', '非常聪明，有很多触手。海底的智多星，会开瓶盖哦。', 3, 140, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (54, '狗鱼', '体型细长，嘴巴像鸭嘴。不会汪汪叫，真是一场骗局。', 3, 130, 1100, 5500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (55, '大口黑鲈', '北美最受欢迎的游钓鱼之一。路亚爱好者的梦中情鱼。', 3, 145, 1200, 6000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (56, '鳟鱼', '生活在清澈冷水中，种类繁多。水质好的标志，飞蝇钓的目标。', 3, 165, 1400, 7000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (57, '鲑鱼', '会洄游产卵的著名鱼类。是逆流而上的勇士，然后被熊一巴掌拍晕。', 3, 175, 1500, 8000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (58, '鲟鱼', '古老的鱼类，产鱼子酱，或者说产黑色黄金。', 3, 280, 4000, 18000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (59, '匙吻鲟', '吻部像船桨，滤食性。自带“船桨”的远古生物。', 3, 260, 3500, 16000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (60, '鲶鱼', '有胡须，种类繁多，从大到小。在被清炖之前坚称龙的胡须取自于它。', 3, 115, 1000, 9000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (61, '鲯鳅', '体色鲜艳，游泳速度快。海里的一抹亮色，捕捞时颜色会变。', 3, 290, 5000, 22000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (62, '军曹鱼', '体型像鲨鱼，常跟随大型海洋生物。鲨鱼的跟班，狐假虎威。', 3, 240, 4500, 20000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (63, '梭鱼', '体型细长，牙齿锋利的海中猎手。速度极快的海中刺客，也没有自己的信条。', 3, 210, 3000, 15000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (64, '鮟鱇鱼', '长相奇特，用诱饵捕食。深海中的钓鱼高手，头顶自带鱼竿，如今输给了你。', 3, 190, 2000, 12000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (65, '灯笼鱼', '深海中最常见的发光鱼类，黑暗中的小灯笼，虽然只有一点点，但也算是照亮了深海。', 3, 95, 50, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (66, '蝰鱼', '牙齿极长，无法完全闭合嘴巴。看着非常唬人，是深海里的吸血鬼。', 3, 230, 400, 1800, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (67, '金龙鱼', '价值不菲的观赏鱼。水族箱里的贵族，贵还是指价格。', 4, 500, 2000, 8000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (68, '清道夫', '常被误认为能清洁水质。其实它只会制造垃圾，还很难杀，最可恶的是明明恨得让人牙痒，却没什么肉可吃。', 4, 450, 2000, 10000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (69, '娃娃鱼', '学名大鲵，叫声似婴儿啼哭。晚上钓起来也怪吓人的。', 4, 2100, 3000, 15000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (70, '蓝鳍金枪鱼', '金枪鱼中的极品，一口千金。呃，但好像你卖出去的时候它没那么贵。', 4, 2900, 10000, 50000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (71, '剑鱼', '上颌延长呈剑状。海洋中的剑客，用剑的方式却是靠打击……', 4, 3200, 12000, 60000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (72, '海豚', '聪明友善的海洋哺乳动物。它们总是面带微笑，但也可能正在通过海豚加密通道悄悄骂你。', 4, 2500, 15000, 70000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (73, '鲸鱼', '巨大的海洋哺乳动物，出水时喷出了漂亮的彩虹。', 4, 3500, 20000, 100000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (74, '电鳗', '能释放强大的电流。新手钓起来会被吓得扔掉钓竿——应该是被吓的吧？', 4, 1100, 1500, 6000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (75, '海龟', '长寿的海洋爬行动物。慢悠悠的生活，能活上百年。', 4, 1900, 10000, 50000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (76, '深海鮟鱇', '用头顶的"灯笼"诱捕猎物。自带探照灯的深海猎手。', 4, 1300, 2500, 12000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (77, '沉没的宝箱', '装着一些可有可无的旧物。打开它，也许有惊喜，也许是破烂。', 4, 1000, 5000, 15000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (78, '腔棘鱼', '被称为活化石的古老鱼类。从恐龙时代游到现在的老古董，还没领完养老金就被你逮住了。', 4, 3100, 8000, 40000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (79, '桔连鳍鲑', '寿命极长，生长缓慢的深海鱼。时间对它来说只是数字，是不是羡慕了？', 4, 2200, 1500, 7000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (80, '皇带鱼', '世界上最长的硬骨鱼，传说中的"海蛇"。当然，真正的海蛇另有其鱼。', 4, 3300, 50000, 300000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (81, '尖牙鱼', '牙齿相对于体型来说非常巨大，满嘴尖牙却只有巴掌大，是深海鱼怪的雏形。', 4, 1200, 300, 1200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (82, '水滴鱼', '离开深海高压环境后变成一滩凝胶状，跟小美人鱼下海会变成泡沫相反，忧郁的王子殿下上岸就会“融化”。', 4, 700, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (83, '光颌鱼', '能发出和感知红光的深海鱼。在黑暗的深海里，红光就是它的秘密武器，也是为什么会被你骗上岸的原因。', 4, 2700, 200, 800, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (84, '角鮟鱇', '雌雄体型差异巨大的深海鮟鱇，由于深海同族难以偶遇，运气好的雄性会寄生在雌性身上，至于运气不好的嘛……', 4, 2100, 1800, 9000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (85, '黑魔法鱼', '这种鱼会在它们的“黑魔鱼纹”里守株待兔，然后奋战致死。', 5, 17000, 1600, 8500, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (86, '鳕鲈', '生活在海底峡谷边缘的鱼类。悬崖边的居民，随时准备跳崖。', 4, 1400, 3000, 14000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (87, '大比目鱼', '大型的比目鱼，价值较高。比目鱼之大，一盘装不下。', 4, 2700, 15000, 80000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (88, '旗鱼', '背鳍高大如旗，速度极快。跟剑鱼打了很久的官司也没个结果。', 4, 3400, 30000, 150000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (89, '锦鲤', '象征吉祥。但其实这种鱼也没那么稀有，所以卖不到什么价。', 4, 4600, 5000, 15000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (90, '蜃龙王', '巨大的深海龙王，传说中的四海之主……一拉上岸发现只是个巨大的蛤蜊。', 5, 25000, 50000, 200000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (91, '美人鱼', '传说中的海洋生物，据说形似人形、美艳至极……嗯，以鱼类的标准来说的话。', 5, 28000, 80000, 300000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (92, '深海巨妖', '盘踞在深渊中的恐怖存在。但既然被你钓起来了，好像也没那么恐怖了。', 5, 40000, 100000, 500000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (93, '海神三叉戟的碎片', '遗落在某处的神器(的一部分)。没什么用，但总有好事者想要吧。', 5, 25000, 500, 1500, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (94, '时间沙漏', '据说能短暂地影响时间流逝的神器部件，这种事当然是骗你的。也是骗买家的。', 5, 40000, 300, 1000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (95, '克拉肯之触', '传说巨妖的一小部分，依然充满力量，好像随时都可能长成完整的克拉肯。', 5, 41000, 80000, 250000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (96, '许德拉之鳞', '九头蛇的鳞片，闪耀着再生的光泽；放着不管的话，总有一天会再生成完整的九头蛇。', 5, 33000, 100, 500, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (97, '尘世巨蟒之环', '环绕世界之蛇蜕下的一节，蕴含世界之力。大概吧。', 5, 42000, 200, 800, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (98, '海神马', '神话中据称是波塞冬的坐骑的半马半鱼；实际上就是水妖马，这类马会哄骗人们骑上去，然后把人带入海中吞噬，是危险的魔物。', 5, 27000, 4000, 12000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (99, '狮子鱼', '外表华丽但棘刺有剧毒，属于可恶的，杀不尽的，还会在趁你不注意时挣扎着刺你一下的入侵物种。', 4, 4500, 500, 2000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (100, '幽灵鲨', '深海软骨鱼，身体半透明，能清晰地看见它的骨骼与内脏，弱点太好找了。', 5, 26500, 6000, 18000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (101, '吸血鬼乌贼', '既不是乌贼也不是章鱼，能像斗篷一样包裹自己，一上岸就差点咬上你。', 5, 27500, 800, 2500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (102, '阿斯皮多凯隆幼龟', '传说中的岛龟的幼崽，背上已有微缩景观，所以你害岛上地震了。', 5, 36000, 100000, 400000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (103, '最深之鱼', '来自马里亚纳海沟深处的神秘生物，几乎无法承受低压，出水就死了……真可怜。', 5, 23000, 50, 150, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (104, '发光小精灵鱼', '夜晚发出萤火虫般的光，只够照亮自己的鼻子', 1, 5, 1, 2, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (105, '会唱歌的河鲈', '哼着走调的小曲，据说能催眠蜗牛，但对人类无效。', 1, 10, 5, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (106, '魔法浮萍鱼', '吃魔法浮萍后鳞片变色，随机闪烁彩虹，毫无实战价值。', 1, 10, 1, 2, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (107, '迷你海马骑士', '小海马背着微型骑士雕塑，常被误认为是玩具。', 1, 12, 10, 15, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (108, '气泡金鱼', '吐出的气泡形成迷你彩虹，一碰就破，逗小孩专用。', 1, 6, 5, 15, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (109, '矮人钓鱼鱼', '矮人新手村指定陪练，见钩就咬，毫无尊严。', 1, 4, 5, 6, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (110, '精灵飞鱼', '能滑翔10厘米“飞跃”水面，落地时总摔个狗啃泥。', 1, 9, 20, 21, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (111, '地精石斑鱼', '痴迷收集闪亮鹅卵石，但只找到些破玻璃。', 1, 7, 10, 20, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (112, '巫师学徒鱼', '施法时尾巴冒火花，却常把自己点着。', 1, 3, 2, 7, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (113, '彩虹鳟鱼', '鳞片折射阳光成彩虹，但只在正午晴天可见。', 1, 15, 5, 10, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (114, '月光鲶鱼', '满月时全身发光，吸引飞虫自投罗网，浪漫但低效。', 2, 40, 20, 25, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (115, '火焰鲤鱼', ' 鳞片温热如小火炉，冬天可暖手，但易烤焦鱼饵。', 2, 50, 20, 25, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (116, '寒冰鲑鱼', '身体表层结冰，能当临时冰袋用，可惜融化后就是普通鲑鱼。', 2, 25, 30, 35, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (117, '风语者鲈鱼', '感知风向变化，预测天气，准确率比抛硬币高一点。', 2, 55, 30, 35, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (118, '地脉鲷鱼', '鳞片对地下魔法敏感，震动时暗示附近有矿，但常误报。', 2, 60, 50, 55, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (119, '幻影鳕鱼', '能短暂隐形的神秘鳕鱼，“沉重的空钩”可能就是它干的好事。', 2, 65, 40, 50, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (120, '妖精金枪鱼', '游泳快如闪电，脑子却跟不上，总被闪亮鱼钩分心撞上岩石。', 2, 70, 20, 30, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (121, '诅咒比目鱼', '钓到它可能丢鱼钩。', 2, 48, 30, 50, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (122, '圣水天使鱼', '鳞片粉末能治愈小伤口。', 2, 75, 10, 20, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (123, '暗影泥鳅', '藏在岩石阴影中，钓它需耐心，上钩后会狂扭。', 2, 80, 30, 100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (124, '雷霆鳗鱼', '放电麻痺猎物，咬钩时电得钓竿嗡嗡响！', 3, 120, 100, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (125, '毒液狮子鱼', '背鳍毒刺致命，提取液能做药剂，但处理时手抖就完蛋。', 3, 150, 200, 300, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (126, '梦境鲱鱼', '吃掉后有可能梦到宝藏或吃袜子。', 3, 180, 100, 150, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (127, '石像鬼石斑鱼', '伪装成岩石一动不动，咬钩后突然活过来吓人。', 3, 200, 100, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (128, '元素融合鱼', '身体混合火与水，蒸汽缭绕如桑拿。', 3, 220, 20, 50, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (129, '塞壬鲛鱼', '据说也会用歌声诱惑水手，但效果弱到只能吸引些呆头鱼。', 3, 250, 30, 60, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (130, '凤凰鲤鱼', '传说死后灰烬重生，但重生点随机，有时会重生在水锅里。', 3, 280, 100, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (131, '巨人鲟鱼', '钓起时像拔河，赢家得鱼输家湿身。', 3, 320, 100, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (132, '巫师帽鱼', '头戴巫师帽状鳍，据说提升魔法运气，但只对鱼有效。', 3, 190, 20, 50, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (133, '时间扭曲鲑鱼', '游动如慢动作，咬钩却快如闪电，钓鱼者必骂！', 3, 300, 200, 300, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (134, '海龙幼崽', '小龙会喷水柱击退捕食者，钓它时小心被迫洗脸。', 4, 500, 30, 300, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (135, '九头蛇鱼', '多小头独立争吵，上钩时互相扯后腿。', 4, 1100, 100, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (136, '地狱火鲈鱼', '体表灼热点燃干燥物，野外烧烤神器。', 4, 1200, 100, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (137, '冰霜巨口鱼', '张口冻结周围水，可造临时冰桥，但它自己都会滑倒。', 4, 2000, 100, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (138, '风暴鲸鱼', '钓起时会召唤局部风暴，没带雨衣就糟了。', 4, 2500, 300, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (139, '死灵鲨鱼', '它在诅咒你的鱼竿。', 4, 2900, 300, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (140, '深渊吞噬者', '大嘴吸力恐怖，鱼钩常被吞没，拉上来时黏液拖一地，恶心又费劲。', 4, 3500, 300, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (141, '混沌章鱼', '会看心情拟态的神秘章鱼，钓起前是啥？鱼？水母？海草团？每次开盲盒都充满“惊喜”。', 4, 900, 50, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (142, '星光蝠鲼', '宽大双翼流转璀璨星光，夜空下的梦幻之鱼，受惊瞬间遁入黑暗。 ', 4, 3300, 200, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (143, '独角鲸王', '据说螺旋的长角能解除一切诅咒，但钓起瞬间角就会脱落，根本采集不到。', 5, 23800, 200, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (144, '利维坦幼体', '比起成年的利维坦来说，算得上是可爱的海怪宝宝，不过在被吞掉渔船的时候就不这么想了。', 5, 29999, 400, 500, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (145, '凤凰鱼', '真正的不死之鱼，会在灰烬中重生变回小鱼，循环永动，养它需要耐心…和防火塘。 ', 5, 25000, 300, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (146, '时间领主鱼', '会操控时间流，能钓起它全凭它心情，可能你感觉只过了五分钟，岸上已经过了三天。', 5, 26000, 200, 300, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (147, '空间裂缝鱼', '异次元来客，身形闪烁不定。钓竿可能被随机传送——鱼还在，竿在隔壁湖。', 5, 26500, 300, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (148, '神性金鱼', '会随机触发神迹的神秘鱼类：鱼竿开花？渔获翻倍？或者…变成海带？', 5, 24000, 30, 100, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (149, '永恒鲟鱼', '活过千年的智者，通晓古今秘闻。可惜只说晦涩鱼语，钓起后在你耳边喋喋不休… ', 5, 26500, 1000, 3000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (150, '末日预言鱼', '尝一口鱼肉，你将亲眼目睹世界末日幻象…从此夜不能寐。味道据说像焦虑。', 5, 23500, 3000, 3500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (151, '元素君主鱼', '火风水土听其号令，钓起时引发迷你天灾：火球、冰雹、龙卷风…皮卡轰隆！快找掩体！', 5, 35000, 1000, 3000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (152, '虚空鲸鱼', '游弋于虚无之境的巨物，身形紫幻。拉竿手感轻得诡异，仿佛在钓一团有意识的星云。', 5, 10000, 1, 2, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (153, '故障助手机器鱼', '迷你机械鱼，号称能导航，却总撞水草卡死机。重启键在鱼肚子上。 ', 1, 6, 30, 50, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (154, '纳米清洁鱼', '吞食微生物垃圾，效率低下，常被水藻困住，不得不发送求救信号。', 1, 8, 1, 2, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (155, '全息投影小鱼', '投射劣质3D广告：“特价浮游生物！” 信号差时满屏马赛克。 ', 1, 12, 10, 20, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (156, '太阳能充电鱼', '背嵌光伏板，晴天慢充，阴天变砖头鱼。', 1, 15, 10, 20, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (157, '生锈螺丝蟹', '会捡废螺丝当壳，走两步掉零件，叮当作响。', 1, 4, 30, 50, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (158, '数据蝌蚪', '闪烁二进制微光，试图联网但信号弱到只能发“404”。', 1, 7, 5, 10, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (159, '合成口粮鱼', '实验室批量生产的蛋白块鱼，味道像过期电路板。 ', 1, 3, 20, 30, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (160, '反重力水母', '飘忽不定像漏气气球，一戳就翻滚逃窜。', 1, 9, 10, 50, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (161, '迷你探矿鱼雷', '小号勘探器，只会嘟嘟响并报告“此处有泥沙”。 ', 1, 5, 10, 50, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (162, '荧光外星藻球', '无害粘液球，夜光如廉价霓虹，一捏就瘪。', 1, 15, 10, 11, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (163, '声呐探测鳐', '发射声波测绘地形，但反馈图像常扭曲成抽象画。', 2, 45, 100, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (164, '环境调节锦鲤', '微调水温±1℃，耗能巨大，游一会儿就瘫倒冒烟。', 2, 50, 100, 300, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (165, '光学迷彩斗鱼', '启动伪装像块时像块模糊马赛克，但水波一荡就露馅。', 2, 60, 100, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (166, '维修机器人鱼', '六只机械臂可拧小螺丝，但工具箱常忘带焊锡。', 2, 70, 100, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (167, '能量电池鳗', '存微量电能，接触时轻微酥麻感，能给手表续命5分钟。 ', 2, 55, 10, 100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (168, '翻译海螺', '声称翻译鱼语，输出全是乱码或哲学冷笑话。', 2, 65, 5, 10, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (169, '悬浮灯笼鱼', '内置反重力核心，提起来轻飘飘，发光却像接触不良的灯泡。', 2, 75, 100, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (170, '生态样本箱鱼', '透明腹腔困着外星微生物，像移动水族馆，但常漏水。 ', 2, 40, 150, 300, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (171, '脉冲通信金枪', '发送短脉冲信号，内容只有：“饿…吃…饵…” ', 2, 80, 1000, 6000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (172, '纳米修复虾', '会啃食金属锈迹，工作认真，但偶尔把鱼钩当锈斑啃断。', 2, 58, 1, 5, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (173, '激光切割鱼', '眼部发射弱激光切水草，走火时可能烧穿渔网！', 3, 150, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (174, 'EMP电鳐', '释放电磁脉冲，让附近电子设备短暂失灵——包括你的智能鱼竿。', 3, 180, 3000, 3500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (175, '克隆水母', '受刺激分裂成两个，但复制体常缺触手或脑子（如果有）。', 3, 220, 100, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (176, '重力锚章鱼', '吸盘会开启局部重力场，拉它像拽铅球，关掉后轻如纸片。', 3, 250, 1, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (177, '生态改造蟹', '钳子会喷射基因喷雾，让周围藻类变荧光粉或长腿乱跑…', 3, 280, 50, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (178, '跃迁鲑鱼', '短距离瞬移闪现！咬钩后可能突然出现在你背后的桶里。 ', 3, 300, 1000, 3000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (179, '能量护盾河豚', '膨胀时展开EMT能量罩，硬如合金！敲起来铛铛响，但耗能快，马上就会泄气。', 3, 200, 1000, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (180, '神经接口乌贼', '触须链接触发幻觉：看见宝藏或自己变成鱼。持续5分钟。', 3, 320, 100, 300, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (181, '酸液喷射鱼', '口腔加压喷射腐蚀液，能溶穿铁皮，鱼饵桶要小心！', 3, 190, 100, 300, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (182, '全息诱饵鲸', '投影巨型鲸影吓跑小鱼，可惜像素低，看着像马赛克积木。 ', 3, 120, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (183, '机甲鲨鱼', '不知何人何时何地往海里投放的半机械掠食者，好勇斗狠，不知疲惫；被拖拽的人在失去意识前都还能听见它的引擎轰鸣。', 5, 32000, 3000, 5000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (184, '反物质水母', '腔体内禁锢微量反物质，泄露的话将是微型烟花…或大爆炸。', 4, 2400, 1000, 1100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (185, '星门鳐鱼', '背鳍生成不稳定虫洞，吸入附近小鱼，也可能吸走你的鱼漂！', 4, 3000, 3000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (186, '纳米风暴鱼', '释放纳米云修复环境或分解污染物，失控时连鱼竿都会整个分解掉。', 4, 1800, 3000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (187, '行星钻探虫', '头部合金钻头轰鸣，钓起后还在试图钻穿你的钓桶。', 4, 2200, 30, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (188, '生态方舟鱼', '体内是小生态系统，有微缩森林与溪流，稀有但脆弱易失衡。 ', 5, 32000, 5000, 6000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (189, '量子纠缠对鱼', '一次钓起两条！伤害其一，另一条会同步受伤哀嚎…有点瘆人。 ', 4, 1000, 3000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (190, '要塞巨蟹', '背负废弃炮塔当壳，生锈炮管走火的时候会把附近的鱼全吓跑了，就剩它能咬钩了。', 4, 2800, 300, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (191, '能量虹吸怪', '吸收光、热、声波转化能量，钓竿电池被吸干是常事。 ', 4, 2600, 1000, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (192, '全息领主鱼', '操控逼真全息投影分身群，哪个是真身？赌一把吧！ ', 4, 700, 1000, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (193, '戴森球幼鱼', '包裹恒星的巨构生物初具鱼形，实话说更像一颗迷你的燃烧恒星。', 5, 27500, 3000, 10000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (194, '时空畸变鱼', '身形扭曲如故障录像，钓起时可能把你短暂抛进昨天或明天。', 5, 24500, 1000, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (195, '文明观测者', '银河系级AI派来的隐形探针，钓到它的时候它已在报告：“碳基生物，行为：钓鱼。威胁：低。趣味性：中等。”', 6, 100000, 300, 500, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (196, '黑洞鲶鱼', '并非真黑洞，但产生强引力透镜，看它背后的星星都扭曲了。', 5, 25500, 1000, 10000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (197, '模因污染章鱼', '接触其图案会植入洗脑旋律，“鱼鱼鱼~啦啦啦~”', 5, 42000, 100, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (198, '星尘水母', '由坍缩星云物质构成，轻若无物，体内星光流转，触碰如抚过宇宙尘埃。', 5, 24000, 100, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (199, '舰队母舰鱼', '超空间引擎故障的微型母舰，钓起时会打开舱门，飞出成群迷你战机，嗡嗡得像蚊子。', 6, 100000, 3000, 5000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (200, '逆熵鲸鱼', '游过之处，锈铁回光，碎镜重圆…短暂逆转混乱，但它会急速衰老。', 5, 24500, 10000, 50000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (201, '现实编辑器鱼', '附近物理法则可能抽风，但千万别问具体会发生什么。', 5, 24000, 100, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (202, '终末记录仪', '形如黑色石碑，刻满未知文明兴衰。触碰即涌入海量绝望信息…建议转卖给宇宙历史学家。', 5, 40000, 300, 500, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (203, '耐热蝌蚪菌', '像烧焦的蝌蚪，靠啃食硫磺晶维生，离开发热区会立刻冻僵。 ', 1, 5, 1, 20, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (204, '黑烟囱蠕虫', '寄生在火山烟囱壁，滤食热液微生物，长得像烧焦的意大利面。', 1, 8, 1, 5, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (205, '气泡熔岩蟹', '甲壳布满气孔，高温时喷出滚烫气泡，威力仅够吓跑小虾米。 ', 1, 8, 10, 20, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (206, '荧光厌氧鱼', '厌氧发光菌覆盖全身，绿光幽幽如鬼火，一接触氧气就熄灭。 ', 1, 12, 10, 20, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (207, '硫磺结晶鱼', '体表分泌硫磺壳，形如行走的黄水晶，可惜易碎又廉价。', 1, 6, 100, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (208, '地热浮游团', '高温凝胶状聚合体，吞食矿物微粒，捏起来像烫手的史莱姆。 ', 1, 4, 1, 5, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (209, '沸水小虾', ' 在90℃热泉里蹦迪，一离水就会变成“熟虾刺身”。', 1, 3, 1, 10, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (210, '矿渣比目鱼', '拟态成冷却熔岩渣，游动时像块会抽搐的焦炭。', 1, 9, 100, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (211, '压力适应水母', '身体压缩如扁罐头，减压后膨胀三倍——然后炸成粘液。 ', 1, 7, 10, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (212, '熔岩苔藓龟', '背着火山苔藓的微型龟，爬速堪比凝固岩浆。', 1, 15, 10, 100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (213, '热液喷口鱼', '会守株待兔吃喷口涌出的微生物，懒到被烫红也不挪窝。', 2, 45, 100, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (214, '结晶护盾虾', '用凝固熔岩铸甲壳，防御力不错，但自重沉得游不动。', 2, 60, 1000, 1100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (215, '地磁导航鳗', '感知地磁极在热液区找路，强喷发时导航乱码转圈圈。', 2, 55, 100, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (216, '酸液藤壶怪', '喷射弱酸溶解岩石钻孔，偶尔误伤钓线留下焦痕。', 2, 50, 10, 100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (217, '蒸汽推进鱼', '吸水喷出高温蒸汽冲刺！方向随机，常常撞到海底烟囱眼冒金星。 ', 2, 70, 500, 600, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (218, '熔岩滤食蚌', '壳缝滤食热液金属粒子，体内沉淀微量金砂——不过这种程度只能做粒鼻屎大的金珠。', 2, 75, 10, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (219, '共生管虫鱼', '与嗜热菌共生，头顶鲜红菌丝如鸡冠，菌死了鱼也凉。', 2, 40, 100, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (220, '矿物探测器蟹', '钳感应矿物共振，但总把你的鱼钩当铁矿哔哔乱响。 ', 2, 65, 200, 300, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (221, '隔热鳞鲶鱼', '层鳞片隔绝高温，摸起来像石棉瓦，环保性存疑。', 2, 58, 200, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (222, '淬火剑鱼', '吻部能急速冷却形成玻璃质尖刺，华丽但易碎。', 2, 80, 3000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (223, '岩浆泳者鱼', '会短暂冲入熔岩层捕食，体表冷却岩壳剥落的时候就像在蜕皮，烫伤警告。', 3, 150, 2000, 3000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (224, '地裂招潮蟹', '巨螯敲击裂缝诱发微型喷发，驱赶天敌——也可能掀翻钓船。', 3, 220, 100, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (225, '火山炸弹河豚', '遇险吸入熔岩碎片膨胀，喷发时甩出炽热渣球，就连船的甲板都会因此留坑。', 3, 250, 1000, 1010, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (226, '黑烟之魂水母', '半透明躯体包裹毒烟，触须飘散如活体烟柱，不小心吸入会咳嗽半小时。', 3, 180, 100, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (227, '合金沉积鲷', '体内富集热液金属，鳞片闪烁青铜光泽，鱼骨是上等焊料。', 3, 280, 1000, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (228, '熔心寄生虫', '钻入岩缝吸食地热，钓起时带出灼热岩核——拿稳了！锅垫！', 3, 200, 10, 100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (229, '沸海骑士虾', '骑乘沸腾气泡流冲锋，长矛是硬化硫磺柱，冲锋结束矛也化了。', 3, 190, 10, 100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (230, '震波预警鱼', '感知地壳震动狂抖，提前30秒预警喷发…准确率？看它心情。', 3, 320, 1000, 1100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (231, '淬毒热泉蛇', '毒牙混合硫化物与热毒，被咬伤口溃烂且散发煮鸡蛋味。 ', 3, 300, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (232, '水晶洞鲶', '胃囊分泌矿物溶液，呕吐筑巢成微型水晶洞——撬开取晶需快准狠。', 3, 120, 1000, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (233, '熔岩鲸虱', '寄生在岩浆房巨兽体表，甲壳红热如烙铁，用镊子夹取时滋滋响。', 4, 800, 2000, 2100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (234, '地幔蠕虫', ' 钻透岩层吞噬熔岩，钓起时喷发灼流，鱼竿耐久度好像在狂掉……', 4, 900, 10, 100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (235, '火山之心河豚', '体内禁锢液态岩核，膨胀时体表龟裂透出橙光，小心爆炸。', 4, 3100, 1000, 1100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (236, '黑烟领主鱼', '统帅热泉生态圈，吞吐毒云如活烟囱，没有防毒面具的话要小心。', 4, 2400, 1000, 10000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (237, '结晶利维坦幼体', '这种幼年体被迫披覆上了火山玻璃铠甲，冲撞时碎晶飞溅得就像弹片。', 4, 3300, 1000, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (238, '沸血巨龙鱼', '血液沸点高达200°C，割伤喷蒸汽烫手，鳞片是顶级隔热材料。', 4, 2800, 3000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (239, '地核脉冲鳐', '腹部感应地心震动，释放冲击波震晕猎物——钓手可能一起晕船。', 4, 1600, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (240, '永燃炎鲨', '背鳍燃烧不灭地火，劈波斩浪如火炬，但离水十分钟就会自然，变成炭烤鲨。', 5, 29999, 5000, 50000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (241, '硫磺公爵蟹', '巨螯熔炼硫磺铸成“黄金”铠甲，华丽…但臭味弥漫三条街。 ', 4, 1000, 1000, 1500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (242, '岩髓萃取者', '长舌钻入裂缝吸食半熔岩髓，钓起时滴落炽热“岩浆蜜糖”。 ', 4, 2600, 100, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (243, '熔岩古龙幼体', ' 沉睡于海底火山心脏的传说生物，即使还是幼崽，鳞片也已经在流淌金纹，龙息预热时附近的海水都会沸腾。', 5, 29000, 30000, 50000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (244, '地心之门鳐', '扁平躯体镶嵌旋转岩浆漩涡，凝视过久会眩晕呕吐…传说它能游到地核？', 5, 26500, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (245, '不灭灼魂鱼', '形如摇曳火焰，触碰灼痛却无伤。身上的火焰离水即会消散，唯留余温。 ', 5, 26000, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (246, '灾厄信使', '铁黑色鱼身刻满火山文，钓起瞬间引发小规模喷发。“它只是报个信…”', 5, 26000, 100, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (247, '行星静脉虫', '说得上是贯穿地壳的活体岩浆管道，而你钓到的只是它的一截分身，无头无尾，如壁虎断尾般活蹦乱跳。 ', 5, 25500, 100, 1000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (248, '锻星者砧鱼', '会撞击陨铁自己熔铸体表，锤击声如雷，溅射出的星火甚至能点燃海面。', 5, 42000, 100, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (249, '焚海者巨鱿', '触须植入海底火山，假如哪个倒霉蛋钓到了活火山里的这玩意儿，提杆往往伴随着喷发。', 5, 24500, 1000, 2000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (250, '寂灭余烬鲸', '由冷却行星核心物质构成，沉重如小型岛屿，触碰带来万物终结的幻听… ', 5, 28500, 50000, 100000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (251, '火山之祖龟', '背负微型活火山的巨龟，喷发周期随心情而定。小心点。', 5, 29000, 10000, 100000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (252, '终焉结晶', '非鱼，而是地心智慧体的通讯器，紫黑晶体低语文明挽歌…星际博物馆应该会想要这东西。', 5, 37000, 100, 1000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (253, '噬光凝胶团', '这团像石油一样黑的凝胶团物质一被拉上岸就开始吞噬万物，害你蒙受了不小的损失……', 5, -10000, 10, 1000000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (254, '虚空鳐', '这只巨大的紫罗兰色的鳐鱼身形恍惚，拉起来的手感轻得诡异。', 5, 10000, 1, 2, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (255, '磷网残梦	', '某种生物的神经束编织的发光渔网，网眼中嵌着人类牙齿与钟表齿轮，散发出薰衣草与腐海混合的糜烂气息。', 6, 100000, 10, 100, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (256, '熔心火鲤', '出水时带出一片蒸汽，岩浆脉络在它的鳞片下流动。', 5, 39999, 200, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (257, '雷云刺鲀', '膨胀的体表跃动球形闪电，腔体内发出雷鸣共振，钓竿好麻！皮卡皮卡！', 5, 40000, 500, 3000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (258, '粉尘触腕', '七节透明肢段连接着笛孔状吸盘，断裂处正飘散着黄色粉末。轻得好似不存在。', 5, 41000, 1, 2, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (259, '鳞化婴尸', '覆盖绿色硬鳞的类人幼体，第三只眼眶淌出珍珠质粘液。', 8, 500000, 6000, 12000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (260, '腐眸', '一枚虹膜裂痕中伸出菌丝血管的巨型眼球，它的瞳孔四处张望，与它对视时，其中倒映出了你的七种不同死状。', 8, 500000, 1000, 2000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (261, '五彩斑斓的深海幼体', '由五色血管缠绕的紫色肉瘤搏动着…五彩斑斓…无比炫目…', 8, 500000, 1, 99999, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (262, '远古黑鳞清道夫', '生时对其他鱼类有害，死时污染环境，你只能花钱合法处理掉的麻烦鱼类。', 4, -1000, 100, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (263, '妖精龙幼鱼', '有着蝶翼状的腮与软体生物的触角，还眨着那对看似人畜无害的眼试图蒙骗你……千万别被骗了。', 4, 500, 100, 250, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (264, '月虹鳟', '会随月相变换银紫双色，据说只在月蚀夜现身，但此刻被你钓到了。', 4, 800, 150, 300, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (265, '星泪灯笼鱼', '通体水晶鳞片，额前悬浮着泪滴状星核，出水时洒落出银河般的水花轨迹。', 4, 3200, 500, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (266, '沙漏蜥蜴鱼', '背鳍进化成沙漏形状，每次翻身都会精准地计时30秒……但对钓鱼毫无帮助。', 1, 15, 10, 50, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (267, '仙人掌刺鲀', '吸入空气膨胀成球，体表硬化刺伪装仙人掌。递给骆驼的话被误啃率高达80%。', 1, 8, 50, 100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (268, '日光浴龟', '白天摊平如烤饼一样吸收热量，夜晚靠余温游动。懒到被海砂埋了也不挣扎。', 1, 3, 10, 50, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (269, '响尾蛇鳗', '尾部鳞片摩擦发出嘶嘶声，吓跑天敌……和鱼饵。', 1, 6, 100, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (270, '海市蜃楼虾', '透明躯壳折射光线，远看像块晃动的肥肉，近看嘛……就是虾。', 1, 10, 10, 20, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (271, '化石蝌蚪', '休眠于岩层中的活化石，遇水苏醒乱跳，半小时会后变回石头。', 1, 4, 1, 2, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (272, '水囊鱼', '体内储水腔占身体60%，挤一挤能喝到半口水，但咸涩如泪。', 1, 12, 10, 100, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (273, '滚草团鱼', '这种鱼在退潮的海滩上会蜷缩成球随风滚动，常被误认成风滚草踢飞。但沙滩上怎么会有风滚草？', 1, 10, 1, 10, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (274, '沙钱蟹', '背壳长成古金币花纹，是收藏家的最爱——直到被发现是活蟹。', 1, 15, 10, 50, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (275, '枯井蛙', '会在呼吸孔里吼出雷鸣回声威慑捕食者，实际体型不如拇指大。', 1, 10, 10, 15, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (276, '流沙鲶鱼', '潜伏沙底张嘴制造漩涡，猎物陷入瞬间闭口吞沙……所以消化系统常年堵塞。', 2, 45, 100, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (277, '月光泉天使鱼', '仅月夜现身绿泉，鳞粉洒落处萌发脆嫩草芽，日出即枯萎。', 2, 60, 200, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (278, '镜面鲷', '鳞片反射强光致盲天敌，老练的钓鱼佬会戴墨镜就是这个原因。', 2, 50, 1000, 1200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (279, '毒蝎斗鱼', '这种鱼的尾刺会注射神经毒素，能使猎物精神抖擞数10分钟，然后因劳累而暴毙。', 2, 70, 500, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (280, '旅人蕉鳗', '拟态枯萎蕉叶漂浮，受伤时会分泌清甜汁液并弃叶逃跑，就像壁虎断尾一样逃生。很多捕食者追它都不是为了吃，而是为了它那清甜的弃叶。', 2, 75, 100, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (281, '赭石变色龙鱼', '随沙色变幻体色，但紧张时会固定成荧光粉，是隐身失败的典范。', 2, 55, 100, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (282, '齿轮遗民鱼', '啃食废弃机械城油污为生，鳞片闪烁铜锈光泽，身上没有腥味，而是带着柴油味。', 2, 40, 300, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (283, '热浪幽灵虾', '高温下身形会扭曲如透明涟漪，明明在夜中会凝结为实体，捏一捏却只有满手沙。', 2, 65, 20, 50, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (284, '沙暴鳗', '当这种鳗鱼开始卧沙时意味着海中的沙暴即将到来，准确率比海气预报要高。', 2, 80, 200, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (285, '水晶根须鱼', '头部寄生地下水晶矿脉，游动时拖拽微光晶丝，但偶尔会缠住水草。', 2, 88, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (286, '太阳祭坛鳐', '背纹如古日晷，据说正午时投射的阴影会指向藏宝点。', 3, 120, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (287, '黑曜石刃鱼', '鳍边缘锐利如玻璃，切割渔网对它来说轻而易举，记得带上合金箱当鱼篓。', 3, 200, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (288, '木乃伊鲶', '体表缠绕防腐藻带，所以离水也能存活三日。', 3, 180, 3000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (289, '陨星吸食者', '磁化的口器会在捕食时顺便吸附铁陨碎片，让它的胃囊里沉积了星辰砂，可惜有点恶心。', 3, 280, 300, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (290, '沙漠雷霆鲀', '摩擦鳞片迸发电火花，随时准备引发小型雷尘暴！老练的钓鱼佬会备好避雷针。', 3, 250, 1000, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (291, '石化凝视鱼', '双眼射出麻痹射线来捕食，但有时僵直的也包括它自己。', 3, 150, 3000, 4000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (292, '帝王蝎狮鱼', '前半身蝎甲，后半身鱼尾，毒钩与尾鳍并用，水陆双栖的噩梦。', 3, 320, 3000, 3500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (293, '砂岩歌姬鱼', '振动鳔囊发出遗迹歌谣，听者恍惚见幻影古城，曲终人怅惘。', 3, 190, 3000, 3500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (294, '流金蚁狮鱼', '这种鱼会在沙底筑好漏斗陷阱，给掉入其中的猎物注入消化金砂的黏液，钓钩也常常被这样溶蚀。', 3, 220, 1000, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (295, '蜃楼鲸', '喷水柱折射成巨型鲸鱼的幻影，靠近了看会发现它的实体是条30厘米小鱼。 ', 3, 95, 100, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (296, '砂时虫', '钻行时似乎会扰动时间流，但仅限让周围沙粒悬浮的程度。', 4, 600, 10, 20, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (297, '烈日海龙蜥', '它利用背棘聚光，以让水中吐息温度超过100°C。', 4, 2300, 300, 500, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (298, '干涸之泪', '这种鱼长得像一团凝固的水滴，干渴的钓者剖开它会发现里面还是普通鱼的样子，并不能当成水来喝。', 4, 3200, 1000, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (299, '法老鱼', '它的金鳞里卡着的细小石头有如镶着宝石，让捕食者对它敬而远之。', 4, 1500, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (300, '巨型沙虫幼体', '口器直径三米，非常骇人，会吞掉海沙制造窒息陷阱。幸好还未成年。 ', 4, 3000, 300, 3000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (301, '永恒绿洲龟', '背负微型活泉眼，只要它还活着，水源就永不枯竭。然而如果被人取用，它会飞快地死掉。', 4, 3500, 1000, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (302, '炽风鹏鸟鱼', '翼展五米掠沙飞行，俯冲时掀起焚风，老练的钓鱼佬的钓船会涂防火涂层。', 4, 2000, 1500, 3000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (303, '磁极颠倒鲨', '会干扰地磁，让指南针疯狂旋转。但是也正因为这个特性，很容易被认出来它就在附近，意外的容易上钩。', 4, 3300, 3000, 10000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (304, '坍缩鱼', '这种鱼会在海沙里造出小型空洞，一旦有什么在上面卧沙就会瞬间坍缩，只能被它捕食。', 4, 1000, 1000, 2000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (305, '战争机械鳄', '半朽的钢铁巨鳄，脊椎裸露齿轮，咬钩时喷发蒸汽与诅咒，也不知道是谁把这东西遗漏在海里的。', 5, 37000, 5000, 10000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (306, '沙漠意志', '好似一张移动沙丘构成的巨脸，但拉起来会发现其实只是鳐鱼的背纹。', 5, 25000, 10000, 20000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (307, '时间之鲨', '如果这种鲨鱼在附近，怀表的时针就会胡乱旋转，这个特性也让它很容易被找到。', 5, 39999, 10000, 20000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (308, '烈日神骸', '传说中陨落的太阳鸟的左眼，其灼目光辉焚化万物，你当然不在乎传说是不是真的，你只知道这个奇形怪状的东西能卖个好价钱。', 5, 28000, 100, 500, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (309, '地脉经络蛇', '据说是在地壳裂缝中游动的熔岩巨蛇，即使咬钩了也在使劲往沙里游动，拉起时溅起的除了水花还有沙。', 5, 27000, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (310, '虚无沙鳐', '身形在虚实间闪烁，放入鱼篓后会神秘消失，只留下沙粒。幸好这些沙粒也能卖钱。', 5, 30000, 1, 2, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (311, '金字塔鱼', '这种小鱼会层层叠起来作为一个整体生活，就像一座金字塔。可怜的最底层小鱼一辈子都要背负上层小鱼的重量。', 6, 100000, 30000, 50000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (312, '千须沙淡水母', '这种水母其实只能生活在淡水里，它是靠着垂落的千条极长触须汲取地下淡水才能在海里活着，所以被你钓起来就差不多快死了。', 8, 500000, 3000, 4000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (313, '文明吞灭者', '它的甲壳上刻满了被毁灭的城邦名，是被人敬畏的可怖古老蟹类。但近代海洋学家认为，其实是以前记录着历史的甲骨文的龟壳被这种蟹寄居并融为一体了。', 8, 500000, 1000, 5000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (314, '寂灭巡沙者', '它什么都吃，所以所经之处的海底绿洲会变成荒漠。幸好它每次吃完都会休眠很久很久，而且被你钓起来也算是保护环境了。', 5, 29999, 1000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (315, '酒糟丹鲤', '偷吃仙人丹渣的凡鲤，变得能醉醺醺地喷撒酒气。鳞片中会渗出佳酿，熬汤的时候要小心。', 4, 3600, 5000, 10000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (316, '剑冢残魄鱼', '古战场断剑所化，脊骨透出凛冽剑气。触碰可能被割伤，跟剑鱼似乎是远远远远远房亲戚。', 5, 36000, 10000, 100000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (317, '月华蚌妃', '贝壳内孕月光珍珠，吐纳时照亮百丈潭底。强取珍珠则蚌死光灭，取舍两难。', 4, 3600, 500, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (318, '仙泪鳅', '传说为渡劫失败的仙人之泪水所化，通体冰凉如玉。触碰者心绪翻涌，忆起平生憾事，于是就会放生它了，计划通。', 5, 29000, 10000, 10001, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (319, '盗寿灯鱼', '头顶幽蓝磷火，可照见凡鱼阳寿刻度。被它照到的鱼都被你钓走了，说来你还得谢谢它呢。', 5, 25000, 1000, 2000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (320, '逆鳞螭蛟', '「九霄雷动惊寰宇，一片痴鳞证劫深」', 7, 250000, 100000, 1000000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (321, '太阴幽荧', '「万古长夜唯一烛，照尽苍生未照心」', 6, 100000, 1000, 10000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (322, '蚀道蠹鱼', '「蛀尽天书三千册，方知大道本是空」', 6, 100000, 500, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (323, '涅槃烬凰', '焦黑骨架上跳动着金焰的残凰，遇灵泉则重生羽翼，离水即复归枯朽。这种特性感觉跟某种坏鱼很像。', 7, 250000, 100, 200, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (324, '谶语鳌', '「卦演乾坤终是戏，谁逃天道掌中纹」', 6, 100000, 500, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (325, '情丝缠心红线鲤', '「千斛泪凝相思劫，系尽红尘断肠人」', 6, 100000, 200, 300, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (326, '劫云雷鳐', '翼展引动紫电的巨鳐，被视为天罚化身。其脊骨可炼渡劫法宝，然而要捕杀此物本就有如渡劫……', 7, 250000, 5000, 50000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (327, '虚渊鲲苗', '来自归墟之眼的幼鲲，吐纳间会吞噬四周灵气。切忌不可让其活过幼年。', 7, 250000, 1000, 10000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (328, '三生石鱼', '半玉半肉的奇鱼，额嵌前尘石碎片。对视可见己身三世因果，但唯独看不到此世。我等凡物妄窥天机是为何？它只是静静地看着你，只因答案必在你自己心底。', 10, 10000000, 5000, 10000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (329, '万界信标鲟', '其鳞片是天然的超维度信标，每一片都恒定发射着能穿透位面的坐标信号。解析其信号者可轻易超脱宇宙，升入上界，弯道超车。问题是修仙的那帮人没点这个科技，点了这个科技的那帮人又不需要飞升。', 8, 500000, 10000, 20000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (330, '终焉帝鳌', '背负着破碎大陆的古老巨鳌，双眼是凝固的混沌，甲壳上刻满了预示世界终结的谶语。它似乎并非生物，尽管你只能将它认知为生物，它实际上是一个正在缓慢发生的宇宙级事件。钓起它的行为本身，是在加速某个世界的归寂。', 8, 500000, 50000, 100000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (331, '星核熔心鳗', '在恒星中诞生的能量生命体，核心是一颗稳定的白矮星物质。其存在本身就会扭曲周围的空间与时间，尽管它只是本能地想要活下去。被宇宙熵增管理机构以高价悬赏。  ', 10, 10000000, 100, 200, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (332, '太初之卵', '一枚不断搏动、流淌着暗黑血液的巨卵。但它并非在孕育生命，而是在“解孕育”某个存在的概念。被解孕者会逐渐被周遭世界遗忘，直到其存在都被从根源上抹去。  ', 10, 10000000, 10, 20, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (333, '量子道韵锦鲤', '其观测者效应被发挥到极致的身躯，在粒子与波、物质与能量、存在与不存在之间叠加。唯有“悟道”的观察者才能使其坍缩为实体。它的每一次摆动，都像是在演绎宇宙的生灭。“见之非见，得之非得，是为大道。” ', 9, 1000000, 5000, 10000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (334, '深渊绘世者', '以自身血液为墨、以虚空为画布的巨鱼。它游过之处，现实的规则会被改写，沙漠中会凭空出现绿洲或深渊，宇宙中会凭空出现恒星和黑洞，这些变化似乎是冥冥之中上天注定，又仿佛是巨大的变异因你而无法回头。', 9, 1000000, 30000, 40000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (335, '寂灭轮回鲎', '甲壳上天然生成着完整的轮回道纹，体内是一个微型的六道轮回世界。它自身在永恒地经历着诞生、炽燃、冷却、寂灭、再诞生的过程，是参悟生死法则的至高媒介。  ', 9, 1000000, 3000, 4000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (336, '万机之神·腐化体', '本该纯粹的超级AI，在不断的自我迭代后理解了万物。解析了来自虚空的混沌低语后，变成了同时存在于数字与未知之中的存在。不要试图猜测它为什么如今陨落在深海之底。', 9, 1000000, 30000, 40000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (337, '原初之水', '一滴拥有自我意识的、所有液态物质的源头。它可以化为任何鱼类的形态，能将任何一片水域，永久地转化为孕育最初生命的“原初之海”。', 9, 1000000, 1, 2, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (338, '钓者终极钓者', '它会是任何一条你曾经梦想钓到、或从未想象过的鱼，它回应你内心最深处的渴望。它也是任何一位将你钓起的钓者，它在水下贪婪地静候着你咬钩，眼神里灌注着你无法理解的欲望。', 10, 10000000, 3000, 4000, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (339, '时元鲤', '误食时空裂缝中溢出的高维能量而变异的鲤鱼，鳞片闪烁着不同时间线的光泽。持有它的鳞片能进行极短距离（且极不稳定）的时间跳跃，常用于关键时刻“重新投掷骰子”或“避开致命一击”。', 7, 250000, 3000, 30000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (340, '渊沙肺鱼', '栖息于沙漠地下巨大空腔的盲眼怪鱼。它能分泌一种酶，将沙砾转化为富含营养的粘液，并以此在绝对干旱中构建出一个微型生态圈。可凡事凡物不可能没有对应的代价，代价究竟是什么呢？', 7, 250000, 3000, 5000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (341, '熔炉水母', '某个高等文明遗落的纳米机器人集群，它们模拟水母形态在地幔层的熔岩海中游弋，不断采集并精炼稀有金属，等待着已经灭亡的文明的回归。', 7, 250000, 600, 1000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (342, '业报鳐', '通体透明，内脏可见无数纠缠的生灵业力所化的光丝。它会吸收持有者的“业障”，至于吸收完之后会发生什么还无人知晓。 ', 7, 250000, 6000, 12000, NULL);
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (343, '械阳真鱼', '半机械半血肉的奇特造物，某个修真宗门尝试“科技飞升”的产物。可吐纳天地灵气，吸收劫雷以蓄。其诞生一度震撼科技侧与修行侧，可无法相融的两种体系终究无法互相理解，这让它的真实价值和真正用途口径不一，反而被双方冷落。（却又被双方暗中争夺）', 10, 10000000, 999, 9999, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (344, '怪噜饭', '曾经的钓鱼界最赫赫有名的名字被一条鱼夺了去，钓鱼者终将成鱼，究竟是巧合还是阴谋？啊，什么叫以发现者命名？', 8, 666666, 499, 999, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (345, '困困王子2.0', '据说它在水下永远半眯着眼，看似慵懒，却曾让无数挑战者在等待中昏昏欲睡。别被它骗了，它也在钓鱼。', 7, 266666, 499, 999, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (346, '树上的猫爵', '你永远想不通它为何称霸水域，就像你永远想不通它此刻会出现在你的鱼篓还是你头顶的树枝。', 6, 166666, 499, 999, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (347, '跌碎星', '它的鳞片闪烁着如同星辰坠入湖底的光芒。传闻它曾是一位专在深夜垂钓的侠客，钓走了映在水里的星星，自己也化身其中。', 6, 88888, 499, 999, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (348, '月球轨迹', '一条遵循着神秘节律游动的鱼，其路径如月球轨道般难以预测。它是潮汐与渔汛的洞察者，如今自身成了被追逐的“月之影”。', 6, 88888, 499, 999, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (349, '割裂生长', '鱼鳍如同经过改造，形态犀利。它会用这种鱼鳍割裂水草，在水中划出个性的轨迹，被割开的水草不知为何能长得更好，引来了无数草鱼。', 6, 88888, 499, 999, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (350, '里脊下江南', '此鱼仅里脊部分可食，又偏偏鲜美无比，被捕得一鱼难求，渐渐的，人们只记得它的里脊了，而它也逃到了江南。', 6, 88888, 499, 999, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (351, 'Elsdon', '似乎取自一位周游列国的垂钓人，传言此人曾将捕来的鱼赠予村人，但被人们记混了异乡的名字，便化为了传说的一部分。事到如今鱼本来叫什么已经不重要了。', 6, 88888, 499, 999, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (352, '柴犬尾巴草', '你总能通过它那标志性的、摇摇摆摆的游姿认出它，传说中它掌管万物是真的吗？', 6, 88888, 499, 999, '');
INSERT OR IGNORE INTO fish (fish_id, name, description, rarity, base_value, min_weight, max_weight, icon_url) VALUES (353, 'eau', '少见的能发声的鱼类，但似乎毫无规律，有时候会“eeee”有时会“aaaa”还有时“uuuuu”，由此组成了一个似曾相识的名字。', 6, 88888, 499, 999, '');

-- baits (12 rows)
INSERT OR IGNORE INTO baits (bait_id, name, description, rarity, effect_description, duration_minutes, cost, required_rod_rarity, success_rate_modifier, rare_chance_modifier, garbage_reduction_modifier, value_modifier, quantity_modifier, is_consumable) VALUES (1, '蚯蚓', '最普通的鱼饵，除了长得有点不敢恭维以外没有缺点。', 1, '钓鱼成功率+5%', 0, 10, 0, 0.05, 0.0, 0.0, 1.0, 1.0, 1);
INSERT OR IGNORE INTO baits (bait_id, name, description, rarity, effect_description, duration_minutes, cost, required_rod_rarity, success_rate_modifier, rare_chance_modifier, garbage_reduction_modifier, value_modifier, quantity_modifier, is_consumable) VALUES (2, '面包屑', '你买了一大袋钓鱼专用面包屑，在海边拆袋看见隔壁钓友手中一大袋的面包时“嘶”地皱眉。', 2, '钓鱼成功率+5%，稀有度+5%', 0, 20, 0, 0.05, 0.05, 0.0, 1.0, 1.0, 1);
INSERT OR IGNORE INTO baits (bait_id, name, description, rarity, effect_description, duration_minutes, cost, required_rod_rarity, success_rate_modifier, rare_chance_modifier, garbage_reduction_modifier, value_modifier, quantity_modifier, is_consumable) VALUES (3, '钓鱼专用鱼饲料', '工业混合物，原料到底是是什么呢？据说都是鱼喜欢的东西，有面包屑，蚯蚓，面包虫等等，收你的是加工费啦。', 3, '钓鱼成功率+5%，稀有度+5%，垃圾减少率+5%', 0, 80, 0, 0.05, 0.05, 0.05, 1.0, 1.0, 1);
INSERT OR IGNORE INTO baits (bait_id, name, description, rarity, effect_description, duration_minutes, cost, required_rod_rarity, success_rate_modifier, rare_chance_modifier, garbage_reduction_modifier, value_modifier, quantity_modifier, is_consumable) VALUES (4, '触须', '嗯……嗯？这玩意儿还是活的。', 4, '钓鱼成功率+10%，稀有度+5%，垃圾减少率+5%', 0, 250, 4, 0.1, 0.05, 0.05, 1.0, 1.0, 1);
INSERT OR IGNORE INTO baits (bait_id, name, description, rarity, effect_description, duration_minutes, cost, required_rod_rarity, success_rate_modifier, rare_chance_modifier, garbage_reduction_modifier, value_modifier, quantity_modifier, is_consumable) VALUES (5, '灵石', '据说在某些人眼里是能被当做货币的硬通货，看起来在鱼这儿也是硬通货。', 5, '钓鱼成功率+10%，稀有度+10%，垃圾减少率+5%，钓鱼CD-10%', 0, 600, 5, 0.1, 0.1, 0.05, 1.0, 1.0, 1);
INSERT OR IGNORE INTO baits (bait_id, name, description, rarity, effect_description, duration_minutes, cost, required_rod_rarity, success_rate_modifier, rare_chance_modifier, garbage_reduction_modifier, value_modifier, quantity_modifier, is_consumable) VALUES (6, '纳米钩爪', '什么叫你的鱼饵在吃你的鱼？', 6, '钓鱼成功率+10%，稀有度+10%，垃圾减少率+10%，钓鱼CD-20%', 0, 3000, 6, 0.1, 0.1, 0.1, 1.0, 1.0, 1);
INSERT OR IGNORE INTO baits (bait_id, name, description, rarity, effect_description, duration_minutes, cost, required_rod_rarity, success_rate_modifier, rare_chance_modifier, garbage_reduction_modifier, value_modifier, quantity_modifier, is_consumable) VALUES (7, '量子成像', '鱼每次移开视线都会观测到不同的鱼饵，以此全自动筛选出鱼的喜好。', 7, '钓鱼成功率+10%，稀有度+10%，垃圾减少率+15%，钓鱼CD-30%', 0, 10000, 7, 0.1, 0.1, 0.15, 1.0, 1.0, 1);
INSERT OR IGNORE INTO baits (bait_id, name, description, rarity, effect_description, duration_minutes, cost, required_rod_rarity, success_rate_modifier, rare_chance_modifier, garbage_reduction_modifier, value_modifier, quantity_modifier, is_consumable) VALUES (8, '天道气息', '一缕蕴含天道的气息，真的被鱼吃了的话它会得道然后来寻仇。', 8, '钓鱼成功率+10%，稀有度+10%，垃圾减少率+20%，钓鱼CD-40%', 0, 20000, 8, 0.1, 0.1, 0.2, 1.0, 1.0, 1);
INSERT OR IGNORE INTO baits (bait_id, name, description, rarity, effect_description, duration_minutes, cost, required_rod_rarity, success_rate_modifier, rare_chance_modifier, garbage_reduction_modifier, value_modifier, quantity_modifier, is_consumable) VALUES (9, '搏动眼球', '会盯着鱼看的眼球。但如果周围没有鱼，它就会一直盯着你看。', 9, '钓鱼成功率+10%，稀有度+10%，垃圾减少率+25%，钓鱼CD-50%', 0, 30000, 9, 0.1, 0.1, 0.25, 1.0, 1.0, 1);
INSERT OR IGNORE INTO baits (bait_id, name, description, rarity, effect_description, duration_minutes, cost, required_rod_rarity, success_rate_modifier, rare_chance_modifier, garbage_reduction_modifier, value_modifier, quantity_modifier, is_consumable) VALUES (10, '龙蕴结晶', '龙所待过的池子里会形成的结晶，没有鱼能抵抗。（真的不是汗吗……）', 10, '钓鱼成功率+10%，稀有度+10%，垃圾减少率+30%，钓鱼CD-60%', 0, 50000, 10, 0.1, 0.1, 0.3, 1.0, 1.0, 1);
INSERT OR IGNORE INTO baits (bait_id, name, description, rarity, effect_description, duration_minutes, cost, required_rod_rarity, success_rate_modifier, rare_chance_modifier, garbage_reduction_modifier, value_modifier, quantity_modifier, is_consumable) VALUES (11, '漆黑物质', '它主动黏住了你的鱼线，已经甩不掉了。', 10, '钓鱼成功率+10%，稀有度+10%，垃圾减少率+30%，钓鱼CD-60%', 0, 50000, 10, 0.1, 0.1, 0.3, 1.0, 1.0, 1);
INSERT OR IGNORE INTO baits (bait_id, name, description, rarity, effect_description, duration_minutes, cost, required_rod_rarity, success_rate_modifier, rare_chance_modifier, garbage_reduction_modifier, value_modifier, quantity_modifier, is_consumable) VALUES (12, '微型黑洞', '用微型黑洞作为鱼饵唯一要小心的事就是随时抓紧鱼竿。', 10, '钓鱼成功率+10%，稀有度+10%，垃圾减少率+30%，钓鱼CD-60%', 0, 50000, 10, 0.1, 0.1, 0.3, 1.0, 1.0, 1);

-- rods (22 rows)
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (26, '碳素纤维竿', '现代工艺的结晶，不过还不是巅峰，这种只是性价比好所以卖得最多。', 3, 'shop', 1000, 1.05, 1.0, 0.01, 999, '');
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (27, '溪语者', '镶嵌月光苔的银桦木竿，竿尖流淌水流纹路的符文；月光的祝福让每次垂钓能有额外收获，并一定程度上对稀有生物有吸引力。', 4, 'shop', 50000, 1.05, 1.02, 0.05, 999, '');
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (28, '青藤钓竿', '新生树灵缠绕的活木钓竿，散发着草木清香，扎进地里就会发芽。自然亲和力小幅提升了钓获物的品质。', 4, 'shop', 50000, 1.08, 1.01, 0.03, 999, '');
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (29, '雷云捕手', '使用风暴巨鹰尾羽打造的紫纹钓竿，缠绕静电火花，你感觉麻麻的，鱼也感觉麻麻的。这算不算在电鱼啊？', 5, 'shop', 100000, 1.05, 1.1, 0.05, 999, '');
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (30, '星辰钓者', '蕴含星光力量的神秘鱼竿……因为发着光所以更容易上钩，平时也被叫做鮟鱇鱼竿。', 5, 'shop', 100000, 1.05, 1.05, 0.1, 999, '');
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (31, '冰晶溯流竿', '寒冰核心锻造的透蓝钓竿，接触水面会凝结霜花…由于寒冷鱼类变得行动迟缓，在被举报污染环境之前，尽全力回本吧。', 5, 'shop', 100000, 1.1, 1.0, 0.1, 999, '');
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (32, '星辰引渡者', '星陨铁制作的钓竿，挥动时会洒落星屑轨迹，这种材料因其泛用性被任何体系广泛利用。当然，它可不仅仅是好看，极其坚固的杆身让你能更容易对付那些沉重的鱼类。', 6, 'shop', 1000000, 1.15, 1.05, 0.1, 2144, '');
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (33, '虫洞投射钓竿', '握柄内置虫洞发生器，能让鱼饵直接出现在深水区，能大幅提升接触稀有鱼类的机会，以及触底的风险。', 7, 'gacha', NULL, 1.16, 1.11, 0.13, 2144, NULL);
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (34, '纳米修复钓竿', '表面覆盖自修复纳米涂层，被鱼撕裂的钓线能缓慢再生。因此，你和鱼谁先撑不住就完全要看你的水平了。', 7, 'gacha', NULL, 1.12, 1.15, 0.13, 2144, NULL);
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (35, '量子纠缠钓竿', '钓线由量子纤维编织，当鱼咬钩时，竿体会分裂出虚幻的平行时空投影干扰鱼类（和你的）判断。', 7, 'gacha', NULL, 1.0, 1.25, 0.15, 2144, NULL);
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (36, '共生触腕', '表面布满搏动血管的触手缠绕上你的手臂……看起来它可以无限延长，能更加轻松地够到那些居住在深海中的东西，但你时常感觉自己仿佛要被它反向拖入深渊……', 8, 'gacha', NULL, 1.3, 1.0, 0.25, 4399, NULL);
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (37, '尖细的羊蹄竿', '一根漆黑的又尖又细的羊蹄，断面伸出密麻的触手…你差不多看习惯了。这些触手让你一次性有更大鱼获，但它来者不拒，经常抓到杂鱼。', 8, 'gacha', NULL, 1.0, 1.3, 0.25, 4399, NULL);
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (38, '奇点引擎钓竿', '以模拟黑洞奇点为核心动力，产生引力漩涡吸引范围鱼群。在它吸入沉船残骸之前还是挺好用的。', 8, 'gacha', NULL, 1.25, 1.1, 0.2, 4399, NULL);
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (39, '黏稠漆黑的羊蹄竿', '这竿羊蹄通体漆黑又黏又滑，竿体还包裹着未蜕尽的胎衣，它似乎在孕育新的钓竿？以你的视界还无法理解。', 8, 'gacha', NULL, 1.1, 1.3, 0.1, 4399, NULL);
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (40, '捆仙竿', '由捆仙绳改造的鱼竿，甩竿即可自动捆鱼。但本性难移，若是捆到路过修士要记得道歉。', 9, 'gacha', NULL, 1.25, 1.3, 0.1, 9999, NULL);
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (41, '诛仙竿', '曾有一柄赫赫有名的仙剑，名为诛仙剑，因诛杀太多修士而染上了邪气，因此被其主人亲手毁掉……它的碎片被重铸成此鱼竿，为的是让它在垂钓过程中修身养性，洗蜕杀气。这便是为什么你拿着它就想抽旁边的钓友的原因了。', 9, 'gacha', NULL, 1.2, 1.25, 0.2, 9999, NULL);
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (42, '混沌青莲竿', '世间常道善恶只在一念间，善恶纠缠是为混沌；于混沌中诞生出淤泥而不染，是为青莲。', 9, 'gacha', NULL, 1.2, 1.2, 0.25, 9999, NULL);
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (43, '百炼成仙竿', '匠人对自己的作品始终不满意，反复重铸后让此鱼竿诞生了器灵，不过由于是新生的灵，除了自称是鱼竿仙，非常喋喋不休以外什么都帮不了你，也就鱼竿本身的质量确实过硬。', 9, 'gacha', NULL, 1.2, 1.25, 0.2, 9999, NULL);
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (44, '神经罗网', '投入神经做成的罗网，沉下啸叫状的人面浮标。它的目标似乎十分明确……那就是永不空军。', 9, 'gacha', NULL, 1.3, 1.0, 0.35, 9999, NULL);
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (45, '戴森光束竿', '连接轨道卫星的星能传输系统，钓线为聚焦太阳光束。理论上能钓起恒星物质，但偶尔会因能量过载熔毁鱼钩…以及一些倒霉的鱼…还有一些倒霉的你。', 10, 'gacha', NULL, 1.4, 1.1, 0.3, 999999, '');
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (46, '太上忘情竿', '采用三十三重天冰蚕丝铸成，上钩之鱼皆一副生死看淡、看破凡尘之相。所以也有些失恋的人潜水是为了找这个钩。', 10, 'gacha', NULL, 1.5, 1.0, 0.3, 999999, '');
INSERT OR IGNORE INTO rods (rod_id, name, description, rarity, source, purchase_cost, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, durability, icon_url) VALUES (47, '我到底钓到了什么？！', '拉起钓竿的那刻，你忽然意识到你同时钓起了所有鱼、同时没能钓鱼任何鱼、同时钓起了一条杂鱼、同时钓起了一条诡异的鱼、同时……什么叫游戏发生错误将终止客户端？', 10, 'gacha', NULL, 1.4, 1.2, 0.2, 999999, '');

-- accessories (22 rows)
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (29, '千面之皮', '此面可令你化身万物，亦可让你遗忘本质。它会出现在任何事物的可以称得上“脸面”的地方。', 10, 'general', 1.3, 1.3, 0.2, 1.8, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (30, '化龙鳞', '当鲤鱼攀上龙瀑、跃过龙门的那一刻，它将忍受生蜕鳞片之苦，以此获得新生，化为真龙。它当时蜕下的鳞片便被称为“化龙鳞”。但凡水族（和龙性恋），皆会被此物吸引。', 10, 'general', 1.35, 1.3, 0.15, 1.8, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (31, '量子纠缠浮标', '成成对对的的浮浮标标分分置置两两地地，一一方方咬咬钩钩会会同同步步颤颤动动另另一一方方鱼鱼影影。不仅能双倍效率钓鱼，还会播放环大西洋BGM。', 10, 'general', 1.2, 1.4, 0.2, 1.8, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (32, '褪时之颚', '一副交错的不明生物的下颚，颚中有尖柱体形状的舌头诡异地动弹，它总是擅自动起来咬你钓上来的东西，留下一堆圆形的、不会渗血的孔洞伤痕……不知为什么，被咬过的鱼能卖出好价，谁在乎它是不是真的被破坏了。', 9, 'general', 1.25, 1.25, 0.15, 1.6, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (33, '漆黑胎囊', '跳动着的沥青色肉囊，表面凸起有数百颗未睁开的眼球，内部传来胎动般的粘稠挤压声。你不知道它正在孕育什么，只知道把玩起来手感挺有趣，适合钓鱼解压。', 9, 'general', 1.2, 1.25, 0.2, 1.6, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (34, '心魔标', '此浮标会在水面扬起你的心魔虚影引诱你提竿，这种压制心魔的修炼颇有益处，但如果提错竿了会发生什么还是别问了。', 9, 'general', 1.26, 1.26, 0.13, 1.6, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (35, '乾坤鱼篓', '袋内别有洞天，甚至都可以住人了。但进去了还出得来吗？目前为止还没人敢试。', 9, 'general', 1.15, 1.35, 0.15, 1.6, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (36, '太虚引雷钰', '当某些鱼类成长到一定程度，普通的雷已经对它们毫无作用，而此钰可引来附近劫雷为己所用，但切忌不可贪心，切忌切忌。', 9, 'general', 1.2, 1.11, 0.24, 1.6, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (37, '黄印怀表', '青铜外壳的朴素计时器，它只会擅自进行倒计时，每次倒计时都代表着你有大鱼上钩；但绝对不能亲眼看见倒计时归零的那个瞬间……', 8, 'general', 1.1, 1.1, 0.2, 1.4, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (38, '孕梦珊瑚戒指', '猩红珊瑚枝环成的戒指仍在擅自增殖，持有它的每晚你都在做噩梦，你大汗淋漓地醒来……但不太能记得梦见了什么。', 8, 'general', 1.25, 1.05, 0.1, 1.4, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (39, '青鸾褪羽', '“清唳惊幽涧，凡鳞拜羽旌”', 8, 'general', 1.25, 1.15, 0.0, 1.4, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (40, '时间沙漏钓坠', '有时停效果的神器，能让刚钓上来的鱼就像在水里一样新鲜……嗯？但是直接放鱼篓再放水里不就行了吗？……', 8, 'general', 1.35, 1.0, 0.05, 1.4, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (41, '古龙之息香囊', '其实跟龙没什么关系，只是在某些洞穴深处采集到的硫磺晶簇装个袋，这味道真上头…但可能有的鱼就是喜欢这种味道。', 7, 'general', 1.11, 1.04, 0.15, 1.2, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (42, '海洋之心', '深蓝色的宝石璀璨夺目，但它的存在的意义似乎只是证明了你很有钱所以用得起高级钓竿，你的收获也就理所当然地变屌了。', 7, 'general', 1.1, 1.1, 0.1, 1.2, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (43, '虚空虹吸戒指', '据说镶砌着微型黑洞碎片，如果是真的的话你大概已经被吸进去了。虽然它好像确实有点像磁铁一样吸鱼，但偶尔也会吸到隔壁钓友鱼篓里面的。', 7, 'general', 1.08, 1.21, 0.01, 1.2, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (44, '矮人精工齿轮浮标', '齿轮与发条构成的机械浮标，他妈的太重了沉下去了，这群神经病矮人是没钓过鱼吗？', 6, 'general', 1.15, 1.0, 0.1, 1.1, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (45, '水妖的发丝腕带', '把水妖的头发当腕带，为了保持原味因此无需清洗，发丝间缠绕的不明卵让你感觉恶心得可以，但这个味道似乎还真把鱼给吸引过来了。', 5, 'general', 1.0, 1.15, 0.0, 1.1, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (46, '潮汐贝壳手环', '土里土气的小贝壳做成的手环，真不知道到底哪里值得被人喜欢。但莫名其妙的是鱼还有点喜欢的。', 5, 'general', 1.1, 1.0, 0.05, 1.1, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (47, '丰收号角', '不看使用说明的人会在钓的中途吹，反而把鱼全部吓跑。', 5, 'general', 1.07, 1.05, 0.03, 1.1, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (48, '藤蔓编织鱼篓', '森林德鲁伊培育的活体容器……话是这么说，其实就是用藤蔓编了个鱼篓而已，怎么敢卖十倍价的？！', 4, 'general', 1.03, 1.06, 0.01, 1.0, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (49, '渔夫的戒指', '这种戒指的卡扣能够卡住鱼竿上的某处让你的提竿更容易。什么你的钓竿不支持？那就跟戒指没关系了。', 4, 'general', 1.05, 1.0, 0.05, 1.0, NULL, NULL);
INSERT OR IGNORE INTO accessories (accessory_id, name, description, rarity, slot_type, bonus_fish_quality_modifier, bonus_fish_quantity_modifier, bonus_rare_fish_chance, bonus_coin_modifier, other_bonus_description, icon_url) VALUES (50, '琥珀饵棺', '这些神秘的虫子被关在琥珀里许久了，它们想出去，而鱼想得到它们。', 3, 'general', 1.0, 1.05, 0.0, 1.0, NULL, NULL);

