INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (1, '小钱袋', '一个装有少量金币的袋子。', 1, '使用：获得 1000 金币。', 0, 1, NULL, 'ADD_COINS', '{"amount": 1000}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (2, '可疑的转运药水', '五彩斑斓的药水，还有什么是比喝这玩意儿更倒霉的事？', 3, '使用：10分钟内，钓到稀有鱼的概率提升5%。', 0, 1, NULL, 'RARE_FISH_BOOST', '{"duration_seconds": 600, "multiplier": 0.05}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (3, '便携式声呐', '高科技产品，可以立即执行一次钓鱼。', 3, '使用：立即执行一次钓鱼。', 0, 1, NULL, 'RESET_FISHING_COOLDOWN', '{}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (4, '便携式传送门', '一枚小巧的一次性传送门，可以让你再次抓住机会。', 3, '使用：立即重置偷鱼冷却。', 0, 1, NULL, 'RESET_STEAL_COOLDOWN', '{}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (5, '鱼光临海域通行证', '一张由“鱼光临”渔具有限公司发放的一次性通行证，持有此证将被允许进入受其管辖的海域。', 5, '凭此证可进入区域3，每日凌晨需要重新消耗。', 100000, 1, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (6, '擦弹许可证', '一张官方发放的许可证，允许你今天额外进行1次擦弹。', 5, '使用：今天可用的擦弹次数增加1次。', 0, 1, NULL, 'WIPE_BOMB_ATTEMPTS_BOOST', '{"amount": 1}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (7, '中号钱袋', '一个沉甸甸的钱袋，里面装着不少金币。', 2, '使用：获得 10000 金币。', 0, 1, NULL, 'ADD_COINS', '{"amount": 10000}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (8, '大号钱袋', '一个鼓鼓囊囊的大钱袋，非常重。', 3, '使用：获得 50000 金币。', 0, 1, NULL, 'ADD_COINS', '{"amount": 50000}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (9, '神秘钱袋', '一个会变换重量的神秘钱袋，谁也不知道里面有多少钱。', 3, '使用：随机获得 5000 至 20000 金币。', 0, 1, NULL, 'ADD_COINS', '{"min_amount": 5000, "max_amount": 20000}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (10, '巨型钱袋', '一个仿佛装满了全世界财富的巨大袋子。', 4, '使用：随机获得 100000 至 500000 金币！', 0, 1, NULL, 'ADD_COINS', '{"min_amount": 100000, "max_amount": 500000}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (11, '破厄护符·守', '铭刻止厄符文，于炼境崩毁之际护其本体无损。', 4, '获得1次精炼保护（放在背包自动生效，毁坏时改判为普通失败，本体保留不降级）。[仅对5星及以下装备生效]', 0, 0, NULL, 'REFINE_DESTRUCTION_SHIELD', '{"mode": "keep", "max_rarity": 5}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (12, '破厄护符·折', '折锋化险，代价换生机，于崩毁边缘拉回一线。', 4, '获得1次精炼保护（放在背包自动生效，毁坏时改为降一级并保留本体）。', 0, 0, NULL, 'REFINE_DESTRUCTION_SHIELD', '{"mode": "downgrade"}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (13, '天命护符·神佑', '神佑加身，破而不灭。传闻能庇佑至关的一炼。', 5, '获得1次至高保护（放在背包自动生效，任何失败时必改为普通失败，本体保留不降级）。[对所有星级装备均有效]', 0, 0, NULL, 'REFINE_DESTRUCTION_SHIELD', '{"mode": "keep"}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (14, '无面的守护海灵', '召唤一个看起来不太和善的海灵守护你的鱼塘。', 3, '使用：4小时内你的鱼塘不会被其他玩家偷窃。', 0, 1, NULL, 'STEAL_PROTECTION_BUFF', '{"duration_hours": 4}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (15, '伟大种族的未来沙漏', '能毫无代价地窥见未来片刻的奇妙沙漏。但你真的相信它毫无代价吗？', 4, '拨动命运的流沙，一窥未来的吉凶祸福。', 0, 1, NULL, 'FORECAST_WIPE_BOMB', NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (16, '破灵印', '海灵只是讨厌这种印记，并非真的被其克制，一定要注意别太得意了。', 4, '使用：1小时内可以穿透海灵守护进行偷窃。', 0, 1, NULL, 'STEAL_PENETRATION_BUFF', '{"duration_hours": 1}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (17, '驱灵香', '神秘的香料，能够驱散一切守护之力。', 5, '神秘的香料，能够驱散一切守护之力。', 0, 0, NULL, 'STEAL_PROTECTION_REMOVAL', NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (18, '光学斗篷', '一件神秘的斗篷，能够让你在光天化日职中隐秘中行动。', 3, '使用：获得无视海灵守护的反制能力，使用后立即失效。', 0, 1, NULL, 'SHADOW_CLOAK_BUFF', '{}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (19, '千面碎片', '千百种生物皮肤的细小碎片。', 8, '可凭此碎片靠近深渊漩涡。', 1, 1, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (20, '化龙碎片', '化为龙的鲤鱼褪下的残壳碎片。', 8, '可凭此碎片登上龙瀑之巅。', 1, 1, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (21, '全自动工厂污染区域通行证', '钓鱼佬被允许前往该海域通过钓鱼净化水质。谁信。', 7, '凭此证可进入区域4，每日凌晨需要重新消耗。', 1, 1, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (22, '侠盗的符文', '一块刻有模糊不清符文的石片，可以让你再次抓住机会。', 3, '使用：立即重置偷鱼冷却。', 0, 1, NULL, 'RESET_STEAL_COOLDOWN', '{}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (23, '鱼光临海域通行证（终身VIP）', '本公司海域将永远为您开放！招牌里还会写上您的名字！您是我们的神！把钱给我们！', 6, '可永久进入特定钓鱼区域。', 5000000, 0, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (24, '暗影斗篷', '一件神秘的斗篷，能够让你在阴影中行动。', 3, '使用：获得无视海灵守护的反制能力，使用后立即失效。', 0, 1, NULL, 'SHADOW_CLOAK_BUFF', '{}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (25, '幸运药水', '一种神奇的药水，能暂时提升你的运气。', 3, '使用：10分钟内，钓到稀有鱼的概率提升5%。', 0, 0, NULL, 'RARE_FISH_BOOST', '{"duration_seconds": 600, "multiplier": 0.05}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (26, '守护海灵', '召唤一个温和的海灵守护你的鱼塘。', 3, '使用：4小时内你的鱼塘不会被其他玩家偷窃。', 0, 1, NULL, 'STEAL_PROTECTION_BUFF', '{"duration_hours": 4}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (27, '时运沙漏', '一个能窥见未来片刻的奇妙沙漏。', 4, '拨动命运的流沙，一窥未来的吉凶祸福。', 0, 1, NULL, 'FORECAST_WIPE_BOMB', NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (28, '破灵符', '一张古老的符咒，蕴含着破除守护的力量。', 4, '使用：1小时内可以穿透海灵守护进行偷窃。', 0, 1, NULL, 'STEAL_PENETRATION_BUFF', '{"duration_hours": 1}');
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (29, '前往神秘海域的通行证', '一张神秘的通行证，允许进入未知的神秘海域。', 5, '进入特定钓鱼区域时自动消耗。', 0, 0, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (30, '千面碎片（血液凝固）', '被凝固的血液粘在一起，忘记了自己究竟是谁；再也无法分开的千种脸面的碎片。', 10, '可永久进入特定钓鱼区域。', 0, 0, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (31, '化龙碎片（磨砺锋芒）', '鲤鱼化龙时，被龙瀑打磨锋利的鳞片碎片。即可伤及自身，亦可割开瀑布；若惧怕伤痛，则无法凭此鳞逆流而上。', 10, '可永久进入特定钓鱼区域。', 0, 0, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (32, '全自动工厂污染区域通行证（时空错乱）', '这里究竟是未来，还是以前？你唯独能确信的就是这里并非现在。', 10, '可永久进入特定钓鱼区域。', 0, 0, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (33, 'VIP客户专供-鱼光临养殖区通行证', '其实原本用另外一张终身VIP证就可以去的…但上面临时又推出了一种通行证……没想到真的会有人买的大嘴巴员工（第二天被开了）如是说。', 7, '可永久进入特定区域。', 10000000, 0, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (34, '高级犬尾草冻干狗粮', '献给某些生物即可获得自定义专属称号。', 9, '持有该物品并通过.send [自定义称号] 指令发送想要的称号，静候神秘生物前来回收即可。', 0, 0, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (35, '科考许可证（探险）', '由鱼光临鱼类进化科技有限公司发放的科学考察许可证，他们的业务覆盖是不是有点太广了…', 5, '可发起为期一天的探险级科考活动。', 1000000, 1, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (36, '科考许可证（征服）', '对鱼光临的科研团队而言，稳定的特定鱼类获取渠道是非常重要的。仅发放给积累了一定科考实绩的钓鱼佬。', 7, '可发起为期两天的征服级科考活动。', 0, 1, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (37, '科考许可证（圣域）', '传闻中的巨型科研团队所需的巨量特定鱼类只有极巨的钓鱼佬团队才能完成的巨难的科考任务。', 9, '可发起为期三天的圣域级科考活动。', 0, 1, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (38, '科考通行证（探险）', '"鱼光临"为协助科考队员同行而下发的通行证。便宜，量大，但好歹也得有一张。', 3, '加入探险级科考时消耗一张。', 100000, 1, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (39, '科考通行证（征服）', '科考队员入征服级海域的通行凭证。等级越高，鱼光临就越想确保你不是去送死的。', 5, '加入征服级科考时消耗一张。', 0, 1, NULL, NULL, NULL);
INSERT OR IGNORE INTO items (item_id, name, description, rarity, effect_description, cost, is_consumable, icon_url, effect_type, effect_payload) VALUES (40, '科考通行证（圣域）', '能踏入圣域科考海域的通行凭证。本公司不对持证人在圣域内的失踪、消亡或异变负责。', 7, '加入圣域级科考时消耗一张。', 0, 1, NULL, NULL, NULL);

-- gacha_pools (5 rows)
INSERT OR IGNORE INTO gacha_pools (gacha_pool_id, name, description, cost_coins, cost_premium_currency, is_limited_time, open_until) VALUES (1, '黑洞中的扭蛋机', '向黑洞投入量子硬币，转动命运的星轨吧！', 300000, 0, 0, NULL);
INSERT OR IGNORE INTO gacha_pools (gacha_pool_id, name, description, cost_coins, cost_premium_currency, is_limited_time, open_until) VALUES (2, '仙境', '云雾缭绕之地有二，其一如仙境，其二乃魔地。然天机昭昭，俗眼难辨，是仙是魔砸了金币才知道', 600000, 0, 0, NULL);
INSERT OR IGNORE INTO gacha_pools (gacha_pool_id, name, description, cost_coins, cost_premium_currency, is_limited_time, open_until) VALUES (3, '龙泉', '即便蛟龙也会被这通天龙瀑重创，小小鲤鱼为何敢于攀瀑？投入金币的话，也许你也能明白了。', 600000, 0, 0, NULL);
INSERT OR IGNORE INTO gacha_pools (gacha_pool_id, name, description, cost_coins, cost_premium_currency, is_limited_time, open_until) VALUES (4, '深渊', '莫可名状的漆黑触手轻轻触碰到你的衣角，某种呼啸般的声音在呼唤着你深入。', 600000, 0, 0, NULL);
INSERT OR IGNORE INTO gacha_pools (gacha_pool_id, name, description, cost_coins, cost_premium_currency, is_limited_time, open_until) VALUES (5, '梦境', '金币如梦似幻地消失了，那么，你到底得到了什么呢？……', 600000, 0, 0, NULL);

