-- fishing_zones (7 rows)
INSERT OR IGNORE INTO fishing_zones (id, name, description, daily_rare_fish_quota, rare_fish_caught_today, configs, is_active, available_from, available_until, required_item_id, requires_pass, fishing_cost) VALUES (1, '区域一：新手港湾', '刚买到人生第一杆钓竿的人常被推荐的钓点，只能钓到寻常鱼类。', 50, 0, '{"rarity_distribution": [0.6, 0.3, 0.08, 0.02, 0]}', 1, NULL, NULL, NULL, 0, 10);
INSERT OR IGNORE INTO fishing_zones (id, name, description, daily_rare_fish_quota, rare_fish_caught_today, configs, is_active, available_from, available_until, required_item_id, requires_pass, fishing_cost) VALUES (2, '区域二：海峡', '积累了一定钓获后就会被推荐来这里，据说偶尔能钓到不同寻常的鱼。', 2000, 0, '{"rarity_distribution": [0.4, 0.3, 0.2, 0.09, 0.01, 0]}', 1, '', '', NULL, 0, 60);
INSERT OR IGNORE INTO fishing_zones (id, name, description, daily_rare_fish_quota, rare_fish_caught_today, configs, is_active, available_from, available_until, required_item_id, requires_pass, fishing_cost) VALUES (3, '区域三：鱼光临海域', '被鱼光临渔具有限公司控制的海域，需要从他们那购买通行证才可以进入。该死的资本。', 1500, 0, '{"rarity_distribution": [0.3, 0.2, 0.28, 0.17, 0.05, 0]}', 1, '', '', 5, 1, 120);
INSERT OR IGNORE INTO fishing_zones (id, name, description, daily_rare_fish_quota, rare_fish_caught_today, configs, is_active, available_from, available_until, required_item_id, requires_pass, fishing_cost) VALUES (4, '区域四：全自动工厂污染区域', '被久远的工业自动化群排除的污水污染得不成样的海域，有一些独特的鱼生活在这里。', 3000, 0, '{"rarity_distribution": [0.25, 0.25, 0.25, 0.14, 0.1, 0.01]}', 1, '', '', 21, 1, 1000);
INSERT OR IGNORE INTO fishing_zones (id, name, description, daily_rare_fish_quota, rare_fish_caught_today, configs, is_active, available_from, available_until, required_item_id, requires_pass, fishing_cost) VALUES (5, '区域五：云雾缭绕的龙瀑之巅', '传说中鲤鱼化龙之地，此地位处极高，又冷又缺氧，但灵气充裕，修行之鱼会在此停留。', 3000, 0, '{"rarity_distribution": [0.25, 0.25, 0.25, 0.14, 0.1, 0.01]}', 1, '', '', 20, 1, 1000);
INSERT OR IGNORE INTO fishing_zones (id, name, description, daily_rare_fish_quota, rare_fish_caught_today, configs, is_active, available_from, available_until, required_item_id, requires_pass, fishing_cost) VALUES (6, '区域六：莫可名状的深渊之底', '海域中凭空出现的神秘巨大漩涡，宁静得就像寻常海面一般。一些奇特的鱼会在此出没，也不知它们是否是遭到漩涡影响。', 3000, 0, '{"rarity_distribution": [0.25, 0.25, 0.25, 0.14, 0.1, 0.01]}', 1, '', '', 19, 1, 1000);
INSERT OR IGNORE INTO fishing_zones (id, name, description, daily_rare_fish_quota, rare_fish_caught_today, configs, is_active, available_from, available_until, required_item_id, requires_pass, fishing_cost) VALUES (7, '区域三点五：鱼光临海域-VIP专属区域', '为VIP客户开放的特殊区域，资本的大手养殖着一些特殊的鱼类。钓起的鱼最终还是卖给了他们公司，你也分不清到底是你赚了还是他们赚了。', 2000, 0, '{"rarity_distribution": [0.3, 0.3, 0.2, 0.145, 0.05, 0.005]}', 1, '', '', 33, 1, 800);

