-- shops (8 rows)
INSERT OR IGNORE INTO shops (shop_id, name, description, shop_type, is_active, start_time, end_time, daily_start_time, daily_end_time, sort_order) VALUES (1, '“鱼满离”渔具商店', '欢迎光临！使用我们的渔具，鱼一定会满意地离开！', 'normal', 1, NULL, NULL, NULL, NULL, 100);
INSERT OR IGNORE INTO shops (shop_id, name, description, shop_type, is_active, start_time, end_time, daily_start_time, daily_end_time, sort_order) VALUES (2, '“鱼光临”渔具商店', '欢迎光临鱼光临！啊当然，店名并不是在说客人您是鱼的意思！', 'normal', 1, NULL, NULL, NULL, NULL, 100);
INSERT OR IGNORE INTO shops (shop_id, name, description, shop_type, is_active, start_time, end_time, daily_start_time, daily_end_time, sort_order) VALUES (3, '无证经营的渔具商店', '你知道的，朋友，那些资本想的是该怎么降本增效从你的口袋中榨更多钱出来，根本不在乎我们这些手工艺者。我们只能偷偷摸摸地出来卖。', 'limited', 1, NULL, NULL, '21:00', '07:00', 100);
INSERT OR IGNORE INTO shops (shop_id, name, description, shop_type, is_active, start_time, end_time, daily_start_time, daily_end_time, sort_order) VALUES (4, '时空裂隙中的机械臂', '这支机械臂朝你招手，然后向你展示了两种鱼类以及一些科技造物的全息影像。', 'limited', 1, NULL, NULL, '08:00', '14:00', 100);
INSERT OR IGNORE INTO shops (shop_id, name, description, shop_type, is_active, start_time, end_time, daily_start_time, daily_end_time, sort_order) VALUES (5, '龙瀑内的一方洞天', '静候有缘人的奇遇之地。', 'limited', 1, NULL, NULL, '15:00', '20:00', 100);
INSERT OR IGNORE INTO shops (shop_id, name, description, shop_type, is_active, start_time, end_time, daily_start_time, daily_end_time, sort_order) VALUES (6, '幻梦境', '你沉溺于虚幻缥缈又无比真实之梦。', 'limited', 1, NULL, NULL, '21:00', '07:00', 100);
INSERT OR IGNORE INTO shops (shop_id, name, description, shop_type, is_active, start_time, end_time, daily_start_time, daily_end_time, sort_order) VALUES (7, '“鱼光临”渔获商店 ', '听说您钓起了非常特殊的鱼类，请务必让我方高价（大嘘）收购！', 'normal', 1, NULL, NULL, NULL, NULL, 100);
INSERT OR IGNORE INTO shops (shop_id, name, description, shop_type, is_active, start_time, end_time, daily_start_time, daily_end_time, sort_order) VALUES (8, '“鱼光临”科考商店', '诚挚邀请您加入我们的鱼类进化科研项目！当然，为了证明包括资金与周转能力在内的您的实力，只需要一笔小小的入项费……', 'normal', 1, NULL, NULL, NULL, NULL, 100);

