INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (1, 1, '碳素纤维竿', '现代工艺的结晶，不过还不是巅峰，这种只是性价比好所以卖得最多。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (2, 1, '蚯蚓', '最普通的鱼饵，除了长得有点不敢恭维以外没有缺点。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (3, 1, '面包屑', '你买了一大袋钓鱼专用面包屑，在海边拆袋看见隔壁钓友手中一大袋的面包时“嘶”地皱眉。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (4, 1, '琥珀饵棺', '这些神秘的虫子被关在琥珀里许久了，它们想出去，而鱼想得到它们。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (5, 2, '青藤钓竿', '新生树灵缠绕的活木钓竿，散发着草木清香，扎进地里就会发芽。自然亲和力小幅提升了钓获物的品质。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (6, 2, '溪语者', '镶嵌月光苔的银桦木竿，竿尖流淌水流纹路的符文；月光的祝福让每次垂钓能有额外收获，并一定程度上对稀有生物有吸引力。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (7, 2, '钓鱼专用鱼饲料', '工业混合物，原料到底是是什么呢？据说都是鱼喜欢的东西，有面包屑，蚯蚓，面包虫等等，收你的是加工费啦。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (8, 2, '渔夫的戒指', '这种戒指的卡扣能够卡住鱼竿上的某处让你的提竿更容易。什么你的钓竿不支持？那就跟戒指没关系了。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (9, 2, '藤蔓编织鱼篓', '森林德鲁伊培育的活体容器……话是这么说，其实就是用藤蔓编了个鱼篓而已，怎么敢卖十倍价的？！', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (10, 3, '冰晶溯流竿', '寒冰核心锻造的透蓝钓竿，接触水面会凝结霜花…由于寒冷鱼类变得行动迟缓，在被举报污染环境之前，尽全力回本吧。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (12, 3, '星辰钓者', '蕴含星光力量的神秘鱼竿……因为发着光所以更容易上钩，平时也被叫做鮟鱇鱼竿。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (13, 3, '潮汐贝壳手环', '土里土气的小贝壳做成的手环，真不知道到底哪里值得被人喜欢。但莫名其妙的是鱼还有点喜欢的。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (14, 3, '雷云捕手', '使用风暴巨鹰尾羽打造的紫纹钓竿，缠绕静电火花，你感觉麻麻的，鱼也感觉麻麻的。这算不算在电鱼啊？', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (15, 3, '水妖的发丝腕带', '把水妖的头发当腕带，为了保持原味因此无需清洗，发丝间缠绕的不明卵让你感觉恶心得可以，但这个味道似乎还真把鱼给吸引过来了。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (16, 4, '戴森光束竿', '连接轨道卫星的星能传输系统，钓线为聚焦太阳光束。理论上能钓起恒星物质，但偶尔会因能量过载熔毁鱼钩…以及一些倒霉的鱼…还有一些倒霉的你。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (17, 4, '量子纠缠浮标', '成成对对的的浮浮标标分分置置两两地地，一一方方咬咬钩钩会会同同步步颤颤动动另另一一方方鱼鱼影影。不仅能双倍效率钓鱼，还会播放环大西洋BGM。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (19, 5, '太上忘情竿', '采用三十三重天冰蚕丝铸成，上钩之鱼皆一副生死看淡、看破凡尘之相。所以也有些失恋的人潜水是为了找这个钩。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (20, 5, '化龙鳞', '当鲤鱼攀上龙瀑、跃过龙门的那一刻，它将忍受生蜕鳞片之苦，以此获得新生，化为真龙。它当时蜕下的鳞片便被称为“化龙鳞”。但凡水族（和龙性恋），皆会被此物吸引。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (21, 6, '我到底钓到了什么？！', '拉起钓竿的那刻，你忽然意识到你同时钓起了所有鱼、同时没能钓鱼任何鱼、同时钓起了一条杂鱼、同时钓起了一条诡异的鱼、同时……什么叫游戏发生错误将终止客户端？', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (22, 6, '千面之皮', '此面可令你化身万物，亦可让你遗忘本质。它会出现在任何事物的可以称得上“脸面”的地方。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (28, 2, '鱼光临海域通行证', '一张由“鱼光临”渔具有限公司发放的一次性通行证，持有此证将被允许进入受其管辖的海域。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (29, 3, '矮人精工齿轮浮标', '齿轮与发条构成的机械浮标，他妈的太重了沉下去了，这群神经病矮人是没钓过鱼吗？', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (30, 3, '虚空虹吸戒指', '据说镶砌着微型黑洞碎片，如果是真的的话你大概已经被吸进去了。虽然它好像确实有点像磁铁一样吸鱼，但偶尔也会吸到隔壁钓友鱼篓里面的。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (32, 3, '海洋之心', '深蓝色的宝石璀璨夺目，但它的存在的意义似乎只是证明了你很有钱所以用得起高级钓竿，你的收获也就理所当然地变屌了。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (33, 3, '古龙之息香囊', '其实跟龙没什么关系，只是在某些洞穴深处采集到的硫磺晶簇装个袋，这味道真上头…但可能有的鱼就是喜欢这种味道。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (34, 3, '丰收号角', '不看使用说明的人会在钓的中途吹，反而把鱼全部吓跑。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (35, 4, '星辰引渡者', '星陨铁制作的钓竿，挥动时会洒落星屑轨迹，这种材料因其泛用性被任何体系广泛利用。当然，它可不仅仅是好看，极其坚固的杆身让你能更容易对付那些沉重的鱼类。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
