INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (38, 2, '鱼光临海域通行证（终身VIP）', '本公司海域将永远为您开放！招牌里还会写上您的名字！您是我们的神！把钱给我们！', 'general', NULL, 0, NULL, 1, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (39, 4, '全自动工厂污染区域通行证（时空错乱）', '这里究竟是未来，还是以前？你唯独能确信的就是这里并非现在。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (40, 5, '化龙碎片（磨砺锋芒）', '鲤鱼化龙时，被龙瀑打磨锋利的鳞片碎片。即可伤及自身，亦可割开瀑布；若惧怕伤痛，则无法凭此鳞逆流而上。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (41, 6, '千面碎片（血液凝固）', '被凝固的血液粘在一起，忘记了自己究竟是谁；再也无法分开的千种脸面的碎片。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (42, 5, '天地劫火', '集炎火为灵之生齐聚之时，热浪蒸腾，海水沸响，自成一座微缩的暴怒天地。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (43, 5, '一方霸主', '古兽残躯彼此自发共鸣，霸主生灵虎视蠢动；它们各有机缘，如今在争夺残骸的大战中交汇。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (44, 5, '残魄映灯·仙泪冢', '曾有一缕不灭残魄，以魂灯盗寿命，以断剑斩仙泪。寻龙之途遥遥，迷失永无天日。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (45, 4, ' 时空锚点异常', '为便于运输免费提供鱼类隔离舱，但无法保障碳基肢体的时空连续性。回收价将视当前维度稳定性收取稳定税与观测费。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (46, 4, '星际博物馆求购清单', '文明墓碑、恒星雏形、引力异常体、熵增残响。科研与收藏价值极高。提交时请隔离存放，避免鲶鱼将其他藏品“抽象化”。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (47, 4, '生态武装·深海防线', '某些文明建造全自动化工厂阻拦外敌的可能性，由该类可能性构成的多种时间线无法直接观测，仅接收高完整度个体。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (48, 6, '鱼鱼鱼～啦啦啦～', '鱼鱼鱼～啦啦啦～鱼鱼鱼～啦啦啦～鱼鱼鱼～啦啦啦～', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (49, 6, '吞噬万物', '死有余辜。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (50, 6, '存在与不存在之物', '那些只不过是尘埃的鱼类，堆积成了通往深渊的阶梯。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (51, 4, '星际博物馆求购清单·高品质', '如果您有生态保存度更完整的个体，请务必允许我方代星际博物馆收购。注：由于需动用维度运输手段，相关费用将根据您所在维度的稳定性决定。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (52, 7, '全自动工厂污染区域通行证', '客人对那个满是自动化工厂的岛屿感兴趣吗？当然，我们乐意帮助您前往该区域，只需要您展示对应的实力和一点手续费。（所需其一即可）', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (53, 7, '千面碎片', '那是据说如果不持有某种被其召唤的物品，就会遇难的危险区域。但客人您的运气很好！现在只要一点钱，和一些特殊的鱼证明您有在该区域叱咤风云的能力，我们就会保障您的安全！（所需其一即可）', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (54, 7, '化龙碎片', '“寻龙计划2.0”的推进正需要像客人您这样的人才！（客户在该区域遭遇的任何事本公司概不负责）', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (55, 7, '混沌青莲竿', '世间常道善恶只在一念间，善恶纠缠是为混沌；于混沌中诞生出淤泥而不染，是为青莲。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (56, 7, '神经罗网', '投入神经做成的罗网，沉下啸叫状的人面浮标。它的目标似乎十分明确……那就是永不空军。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (57, 7, '奇点引擎钓竿', '以模拟黑洞奇点为核心动力，产生引力漩涡吸引范围鱼群。在它吸入沉船残骸之前还是挺好用的。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (58, 2, 'VIP客户专供-鱼光临养殖区通行证', '其实原本用另外一张终身VIP证就可以去的…但上面临时又推出了一种通行证……没想到真的会有人买的大嘴巴员工（第二天被开了）如是说。', 'general', NULL, 0, NULL, 1, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (59, 5, '寻天道', '何为道？何为天道？不过万物，不过你我。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (60, 4, '拟态采矿机器回收', '建议目标：任何水母；拟态破解方程式：量子筛选；冲突损毁补贴：无', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (61, 6, '别看了。', '别看了。', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (62, 7, '高级犬尾草冻干狗粮', '您对我们的BOSS感兴趣吗？那么我们建议您购买这款…呃，她很喜欢的狗粮！见到我们的BOSS有什么用？嗯，可能她会考虑给你个虚职当称号？', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);
INSERT OR IGNORE INTO shop_items (item_id, shop_id, name, description, category, stock_total, stock_sold, per_user_limit, per_user_daily_limit, is_active, start_time, end_time, sort_order) VALUES (63, 8, '科考许可证（探险）', '您的首次科考活动从这里开始！只要按时按点完成了相应的任务，您绝对不会吃亏！（大概）', 'general', NULL, 0, NULL, NULL, 1, NULL, NULL, 100);

